const getAi = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Robustly parses JSON from model output, handling markdown blocks and extraneous text.
 */
const safeJsonParse = <T>(text: string): T => {
  if (!text) throw new Error("Empty text provided to JSON parser");
  const cleanText = text.trim();

  // 1. Try Direct Parse
  try {
    return JSON.parse(cleanText);
  } catch (e) {
    // Continue to strategies
  }

  // 2. Extract from Markdown Code Block (```json ... ```)
  const codeBlockMatch = cleanText.match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
  if (codeBlockMatch) {
    try {
      return JSON.parse(codeBlockMatch[1].trim());
    } catch (e) {
      // Continue
    }
  }

  // 3. Heuristic Extraction: Find first '{' or '[' and last '}' or ']'
  const firstCurly = cleanText.indexOf('{');
  const firstSquare = cleanText.indexOf('[');

  let startIdx = -1;
  let endIdx = -1;

  // Determine if we are looking for an Object or Array based on which comes first
  if (firstCurly !== -1 && (firstSquare === -1 || firstCurly < firstSquare)) {
    startIdx = firstCurly;
    endIdx = cleanText.lastIndexOf('}');
  } else if (firstSquare !== -1) {
    startIdx = firstSquare;
    endIdx = cleanText.lastIndexOf(']');
  }

  if (startIdx !== -1 && endIdx !== -1 && endIdx > startIdx) {
    const extracted = cleanText.substring(startIdx, endIdx + 1);
    try {
      return JSON.parse(extracted);
    } catch (e) {
      console.warn("Heuristic JSON parse failed", e);
    }
  }

  // 4. Aggressive cleanup as last resort (strip non-json chars from ends)
  // This is risky but handles simple "Here is the JSON: { ... }" cases if regex failed
  try {
      const stripped = cleanText.replace(/^[^{[]+/, '').replace(/[^}\]]+$/, '');
      return JSON.parse(stripped);
  } catch (e) {
      throw new Error(`Failed to parse JSON content: ${text.substring(0, 100)}...`);
  }
};

export const cleanGenAiText = (text: string): string => {
  if (!text) return "";
  let cleaned = text.replace(/^(Below|Here|Following|This) is the (translation|text).*?:/gi, '');
  cleaned = cleaned.replace(/^(以下是|这是).*(翻译|内容).*?：/gi, '');
  return cleaned
    .replace(/\*\*/g, '')
    .replace(/\*/g, '')
    .replace(/`/g, '')
    .replace(/^#+\s/gm, '') 
    .trim();
};

const withRetry = async <T>(fn: () => Promise<T>, retries = 3, delay = 2000): Promise<T> => {
  try {
    return await fn();
  } catch (error: any) {
    const code = error.status || error.response?.status || error.code || 500;
    const message = (error.message || JSON.stringify(error)).toLowerCase();

    console.warn(`Gemini API Request Failed [${code}]. Retries left: ${retries}. Msg: ${message}`);

    const isRetryable = 
      code === 429 || 
      code === 500 || 
      code === 503 || 
      code === 504 ||
      message.includes('overloaded') ||
      message.includes('quota') || 
      message.includes('internal server error') ||
      message.includes('server error') ||
      message.includes('deadline') ||
      message.includes('timeout') ||
      message.includes('unavailable') ||
      message.includes('fetch failed');

    if (retries > 0 && isRetryable) {
      const nextDelay = delay * 2;
      console.log(`Retrying in ${delay}ms...`);
      await new Promise(resolve => setTimeout(resolve, delay));
      return withRetry(fn, retries - 1, nextDelay);
    }
    throw error;
  }
};

const getFilePart = (file: FileContext): Part => {
  if (file.isText) {
    // Limit text to ~1.5M chars to be safe within context window while allowing large books
    const LIMIT = 1500000;
    const content = file.content.length > LIMIT ? file.content.substring(0, LIMIT) + "\n...[Content Truncated]..." : file.content;
    return { text: content };
  }
  return { inlineData: { mimeType: file.mimeType, data: file.content } };
};

export const analyzeBookStructure = async (file: FileContext): Promise<BookStructure> => {
  return withRetry(async () => {
    const ai = getAi();

    // Using gemini-3-pro-preview for superior instruction following on complex extraction tasks
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview", 
      contents: {
        parts: [
          getFilePart(file),
          { text: "Analyze the document structure. Return a valid JSON object with 'title', 'author', and 'chapters' (an array of objects with 'id' (number), 'title' (string), and 'description' (string)). Ensure the JSON is clean and strictly follows this schema." }
        ]
      },
      config: {
        systemInstruction: "You are a specialized document parser. Your output must be ONLY a valid JSON object. Do not include markdown code blocks (```json), conversational text, or introductions. If the document is large, identify the main sections as chapters.",
        responseMimeType: "application/json",
        // Using a schema helps enforce the structure
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            author: { type: Type.STRING },
            chapters: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.INTEGER },
                  title: { type: Type.STRING },
                  description: { type: Type.STRING }
                },
                required: ["id", "title"]
              }
            }
          },
          required: ["title", "author", "chapters"]
        }
      }
    });

    if (!response.text) throw new Error("Empty response from model");

    try {
        const data = safeJsonParse<any>(response.text);

        // Post-processing to ensure data integrity
        if (data.chapters && Array.isArray(data.chapters)) {
            data.chapters = data.chapters.map((c: any, i: number) => ({
                id: typeof c.id === 'number' ? c.id : i + 1,
                title: c.title || `Chapter ${i + 1}`,
                description: c.description || "No description available."
            }));
        } else {
            data.chapters = [];
        }

        return { 
            title: data.title || "Untitled Document",
            author: data.author || "Unknown Author",
            chapters: data.chapters,
            id: crypto.randomUUID(), 
            bookmarks: [] 
        } as BookStructure;

    } catch (e) {
        console.error("Structure Analysis Parse Error:", e, "\nRaw Response:", response.text);
        throw new Error("Failed to parse book structure from AI response.");
    }
  });
};

export const translateSentences = async (sentences: string[], targetLanguage: string): Promise<string[]> => {
  if (sentences.length === 0) return [];
  const batchSize = 10;
  const results: string[] = [];

  for (let i = 0; i < sentences.length; i += batchSize) {
    const batch = sentences.slice(i, i + batchSize);
    const batchResult = await withRetry(async () => {
      const ai = getAi();
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: {
          parts: [{ text: `Translate these sentences to ${targetLanguage}. Return strictly a JSON array of strings.\n\n${JSON.stringify(batch)}` }]
        },
        config: {
          responseMimeType: "application/json",
          thinkingConfig: { thinkingBudget: 0 },
          responseSchema: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        }
      });
      return safeJsonParse<string[]>(response.text || "[]");
    });
    results.push(...batchResult);
    if (i + batchSize < sentences.length) await new Promise(r => setTimeout(r, 200));
  }
  return results;
};

