  const activeFileContext = library.find(item => item.book.id === activeBookId)?.fileContext || null;

  const [activeChapterId, setActiveChapterId] = useState<number | null>(null);
  const activeChapter = activeBook?.chapters.find(c => c.id === activeChapterId) || null;

  const [activeTab, setActiveTab] = useState<Tab>(Tab.AUDIOBOOK);
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [showLibraryList, setShowLibraryList] = useState(false);

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [settings, setSettings] = useState<AppSettings>({
    targetLanguage: 'Spanish',
    highlightColor: 'indigo',
    textSize: 'base',
    lineHeight: 'normal',
    letterSpacing: 'normal',
    font: 'Inter'
  });

  const handleAddToNotebook = (item: Omit<NotebookItem, 'id' | 'timestamp'>) => {
      // Improved classification logic for Words vs Phrases vs Sentences
      let detectedType: 'word' | 'phrase' | 'sentence' = 'word';
      const text = item.text.trim();
      const wordCount = text.split(/\s+/).length;

      if (wordCount === 1 || text.length < 15) {
          detectedType = 'word';
      } else if (wordCount <= 6 && text.length < 50) {
          detectedType = 'phrase';
      } else {
          detectedType = 'sentence';
      }

      const newItem: NotebookItem = {
          ...item,
          id: crypto.randomUUID(),
          timestamp: Date.now(),
          type: detectedType,
          sourceChapter: activeChapter?.title,
          bookTitle: activeBook?.title,
          bookAuthor: activeBook?.author
      };

      setNotebook(prev => [newItem, ...prev]);

      // If no definition is provided (e.g., quick add), fetch one in background
      if (!item.definition) {
          getQuickDefinition(item.text, settings.targetLanguage)
              .then(def => {
                  handleBatchUpdateDefinitions({ [newItem.id]: def });
              })
              .catch(err => {
                  console.error("Auto-definition fetch failed during add:", err);
              });
      }
  };

  const handleDeleteNotebookItem = (id: string) => {
      setNotebook(prev => prev.filter(i => i.id !== id));
  };

  const handleBulkDeleteNotebookItems = (ids: string[]) => {
      setNotebook(prev => prev.filter(i => !ids.includes(i.id)));
  };

  const handleUpdateNotebookComment = (id: string, comment: string) => {
      setNotebook(prev => prev.map(item => item.id === id ? { ...item, comment } : item));
  };

  const handleBatchUpdateDefinitions = (updates: Record<string, string>) => {
      setNotebook(prev => prev.map(item => {
          if (updates[item.id]) {
              return { ...item, definition: updates[item.id] };
          }
          return item;
      }));
  };

  const processEpub = async (file: File): Promise<string> => {
    try {
      const zip = await JSZip.loadAsync(file);

      // Attempt to find the OPF file to determine reading order
      const opfPath = Object.keys(zip.files).find(f => f.toLowerCase().endsWith('.opf'));
      let sortedFiles: string[] = [];
      const parser = new DOMParser();

      if (opfPath) {
          // Robust EPUB Parsing via OPF Spine
          const opfContent = await zip.files[opfPath].async("string");
          const opfDoc = parser.parseFromString(opfContent, "text/xml");

          // 1. Map id -> href (Manifest)
          const manifest: Record<string, string> = {};
          Array.from(opfDoc.getElementsByTagName("item")).forEach(item => {
              const id = item.getAttribute("id");
              const href = item.getAttribute("href");
              if (id && href) manifest[id] = href;
          });

          // 2. Get spine order (idref)
          const spineIds = Array.from(opfDoc.getElementsByTagName("itemref"))
              .map(item => item.getAttribute("idref"))
              .filter(id => id !== null) as string[];

          // 3. Resolve file paths
          const opfDir = opfPath.substring(0, opfPath.lastIndexOf('/') + 1);

          spineIds.forEach(id => {
              if (manifest[id]) {
                  const href = manifest[id];
                  const decodedHref = decodeURIComponent(href);
                  const fullPath = opfDir + decodedHref;

                  if (zip.files[fullPath]) {
                      sortedFiles.push(fullPath);
                  } else {
                      const found = Object.keys(zip.files).find(k => k.endsWith(decodedHref));
                      if (found) sortedFiles.push(found);
                  }
              }
          });
      }

      if (sortedFiles.length === 0) {
          sortedFiles = Object.keys(zip.files).filter(filename => 
            filename.match(/\.(html|xhtml|htm)$/i) && !filename.includes('__MACOSX')
          );
          sortedFiles.sort((a, b) => a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' }));
      }

      let fullText = "";
      for (const filename of sortedFiles) {
        const content = await zip.files[filename].async("string");
        const processedContent = content
            .replace(/<\/p>/gi, '\n\n')
            .replace(/<\/div>/gi, '\n')
            .replace(/<br\s*\/?>/gi, '\n')
            .replace(/<\/h[1-6]>/gi, '\n\n')
            .replace(/<\/li>/gi, '\n');

        const doc = parser.parseFromString(processedContent, "text/html");
        const text = doc.body.textContent || "";
        fullText += text.trim() + "\n\n";
      }

      if (!fullText) throw new Error("No readable text found in EPUB.");
      if (fullText.length > 5000000) {
          return fullText.substring(0, 5000000) + "\n\n[...Content truncated due to excessive size...]";
      }
      return fullText;

    } catch (e) {
      console.error("EPUB processing error", e);
      throw new Error("Could not parse EPUB file. Structure may be corrupted.");
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const allowedExtensions = ['.pdf', '.txt', '.md', '.html', '.xml', '.epub'];
    const hasAllowedExt = allowedExtensions.some(ext => file.name.toLowerCase().endsWith(ext));

    if (!hasAllowedExt) {
      setError("Supported formats: PDF, EPUB, TXT, MD, HTML.");
      return;
    }

    if (!file.type.startsWith('text/') && !file.name.toLowerCase().endsWith('.epub') && file.size > 50 * 1024 * 1024) {
       setError("PDF too large (>50MB). Please optimize or split the file.");
       return;
    }

    setIsProcessing(true);
    setError(null);

    const reader = new FileReader();
    const isEpub = file.name.toLowerCase().endsWith('.epub');
    const isTextBased = file.type.startsWith('text/') || 
                        ['.txt', '.md', '.html', '.xml'].some(ext => file.name.toLowerCase().endsWith(ext));

    const finalizeUpload = async (context: FileContext) => {
        try {
            const structure = await analyzeBookStructure(context);
            const newItem: LibraryItem = {
                book: structure,
                fileContext: context,
                uploadDate: Date.now()
            };
            setLibrary(prev => [newItem, ...prev]);
            setActiveBookId(structure.id);
            if (structure.chapters.length > 0) setActiveChapterId(structure.chapters[0].id);
            setView(AppView.DASHBOARD);
            setShowLibraryList(false);
        } catch (err: any) {
            console.error("Analysis Error:", err);
            setError("Decoding failed. " + (err.message || "The file might be too complex or the model is busy."));
        } finally {
            setIsProcessing(false);
        }
    };

    if (isEpub) {
       try {
         const textContent = await processEpub(file);
         await finalizeUpload({
            content: textContent,
            mimeType: 'text/plain',
            isText: true
         });
       } catch (err: any) {
         setError(err.message || "Failed to process EPUB.");
         setIsProcessing(false);
       }
       return;
    }

    reader.onload = async (e) => {
      let context: FileContext;
      if (isTextBased) {
          let content = e.target?.result as string;
          if (content.length > 2000000) content = content.substring(0, 2000000) + "... [Truncated]";
          context = { content, mimeType: 'text/plain', isText: true };
      } else {
          const rawBase64 = (e.target?.result as string).split(',')[1];
          // Strip newlines and whitespace which are common in base64 output and break API calls
          const cleanBase64 = rawBase64.replace(/[\r\n\s]+/g, '');
          context = { content: cleanBase64, mimeType: 'application/pdf', isText: false };
      }
      await finalizeUpload(context);
    };

    if (isTextBased) reader.readAsText(file);
    else reader.readAsDataURL(file);
  };

  const toggleBookmark = (chapterId: number) => {
    if (!activeBookId) return;
    setLibrary(prev => prev.map(item => {
        if (item.book.id === activeBookId) {
            const bookmarks = item.book.bookmarks || [];
            const isBookmarked = bookmarks.includes(chapterId);
            const newBookmarks = isBookmarked 
                ? bookmarks.filter(id => id !== chapterId)
                : [...bookmarks, chapterId];
            return { ...item, book: { ...item.book, bookmarks: newBookmarks } };
        }
        return item;
    }));
  };

  const renderContent = () => {
    if (activeTab === Tab.NOTEBOOK) {
        return (
            <Notebook 
                items={notebook} 
                onDelete={handleDeleteNotebookItem} 
                onBulkDelete={handleBulkDeleteNotebookItems} 
                onUpdateComment={handleUpdateNotebookComment} 
                onBatchUpdateDefinitions={handleBatchUpdateDefinitions}
                settings={settings} 
            />
        );
    }

    if (!activeChapter || !activeFileContext) return null;

    let content;
    switch (activeTab) {
      case Tab.AUDIOBOOK:
        content = <AudioBook chapter={activeChapter} fileContext={activeFileContext} settings={settings} onSettingsUpdate={setSettings} />;
        break;
      case Tab.PODCAST:
        content = <PodcastPlayer chapter={activeChapter} fileContext={activeFileContext} settings={settings} />;
        break;
      case Tab.CONCEPTS:
        content = <Visualizer chapter={activeChapter} fileContext={activeFileContext} />;
        break;
      case Tab.ANIMATION:
        content = <VideoSummary chapter={activeChapter} fileContext={activeFileContext} />;
        break;
      default:
        content = null;
    }

    return (
      <div key={`${activeBookId}-${activeChapter.id}-${activeTab}`} className="h-full animate-fade-in">
        {content}
      </div>
    );
  };

  if (view === AppView.UPLOAD) {
    return (
      <div className="min-h-screen bg-[#020202] bg-grid flex flex-col items-center justify-center p-6 relative overflow-hidden font-tech text-left">
        <div className="absolute top-8 left-8 w-24 h-24 border-l border-t border-zinc-800 rounded-tl-lg pointer-events-none"></div>
        <div className="absolute bottom-8 right-8 w-24 h-24 border-r border-b border-zinc-800 rounded-br-lg pointer-events-none"></div>

        <div className="z-10 max-w-lg w-full text-center space-y-12">
          <div className="space-y-2 animate-fade-in-up text-center">
             <div className="flex items-center justify-center gap-2 mb-4">
                <Terminal size={32} className="text-[#00f3ff]" />
             </div>
            <h1 className="text-7xl font-bold tracking-tighter text-white drop-shadow-[0_0_25px_rgba(0,243,255,0.3)]">
              Decod<span className="text-[#00f3ff]">Ebook</span>
            </h1>
            <p className="text-zinc-500 tracking-[0.2em] text-xs uppercase">
              V.4.2 // Neural Text Decoding Interface
            </p>
          </div>

          <div className="relative group animate-fade-in-up hud-border bg-[#050505] p-10 transition-all duration-500 hover:shadow-[0_0_30px_rgba(0,243,255,0.1)]" style={{ animationDelay: '0.1s' }}>
              {isProcessing ? (
                <Loader text="DECODING_SOURCE..." />
              ) : (
                <div className="relative flex flex-col items-center justify-center space-y-8">
                  <div className="relative">
                    <div className="w-32 h-32 bg-[#0a0a0c] border border-zinc-800 rounded-full flex items-center justify-center group-hover:border-[#00f3ff] transition-all duration-500">
                        <Upload className="w-12 h-12 text-zinc-600 group-hover:text-[#00f3ff] transition-colors" />
                    </div>
                    <div className="absolute -inset-2 border border-dashed border-zinc-800 rounded-full animate-spin-slow pointer-events-none group-hover:border-[#00f3ff]/30"></div>
                  </div>
                  <div className="space-y-2 text-center">
                    <p className="text-[#00f3ff] font-bold uppercase tracking-widest text-sm animate-pulse">Initialize Upload</p>
                    <p className="text-[10px] text-zinc-600 font-mono">SUPPORTED PROTOCOLS: PDF / EPUB / TXT / MD</p>
                  </div>
                  <input 
                    type="file" 
                    accept=".pdf,.txt,.md,.html,.xml,.epub"
                    onChange={handleFileUpload}
                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                  />
                </div>
              )}
          </div>

          {library.length > 0 && (
             <button 
                onClick={() => setView(AppView.DASHBOARD)}
                className="text-zinc-500 hover:text-[#00f3ff] text-xs font-mono uppercase tracking-widest transition-colors flex items-center gap-2 mx-auto border border-transparent hover:border-[#00f3ff]/30 px-4 py-2 rounded-sm"
             >
                <LibraryIcon size={14} />
                Access_Data_Bank [{library.length}]
             </button>
          )}
          {error && <p className="text-[#ff003c] text-xs font-mono border border-[#ff003c]/30 p-2 bg-[#ff003c]/5">{error}</p>}
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-[#020202] bg-grid text-zinc-300 overflow-hidden font-sans relative text-left">
      <GlobalContextLayer onAddToNotebook={handleAddToNotebook} activeLanguage={settings.targetLanguage} />
      <AIAssistant 
        fileContext={activeFileContext} 
        bookTitle={activeBook?.title} 
        bookId={activeBook?.id} 
      />
      <SettingsModal 
        isOpen={isSettingsOpen} 
        onClose={() => setIsSettingsOpen(false)}
        settings={settings}
        onUpdate={setSettings}
      />

      <aside 
        className={`${isSidebarOpen ? 'w-80' : 'w-0'} bg-[#050505] flex flex-col overflow-hidden relative z-20 transition-all duration-300 border-r border-zinc-900`}
      >
        <div className="p-4 border-b border-zinc-900 shrink-0 bg-black/80 backdrop-blur-sm relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-[1px] bg-[#00f3ff] opacity-20"></div>
            <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-2">
                    <Cpu size={16} className="text-[#00f3ff]" />
                    <span className="text-xs font-tech font-bold text-white tracking-[0.2em]">DECOD.EBOOK</span>
                </div>
                <button 
                    onClick={() => setView(AppView.UPLOAD)} 
                    className="p-1.5 rounded-sm hover:bg-zinc-900 text-zinc-600 hover:text-[#00f3ff] transition-colors"
                    title="Upload New"
                >
                    <Upload size={14} />
                </button>
            </div>
            <div className="flex items-center justify-between mb-2">
                <button 
                onClick={() => setShowLibraryList(!showLibraryList)}
                className={`flex items-center gap-2 text-[10px] font-bold uppercase tracking-widest transition-colors font-tech border px-2 py-1 rounded-sm w-full justify-between ${showLibraryList ? 'text-[#00f3ff] border-[#00f3ff]/50' : 'text-zinc-500 border-zinc-900 hover:border-zinc-700 hover:text-white'}`}
                >
                    <span className="flex items-center gap-2"><Database size={10} /> {showLibraryList ? "SESSION_DATA" : "DATA_BANKS"}</span>
                    <span className="text-[8px] animate-pulse">●</span>
                </button>
            </div>
            {!showLibraryList && activeBook && (
                <div className="mt-4 p-3 border border-zinc-800 bg-zinc-900/20 rounded-sm relative group cursor-default">
                    <div className="absolute top-0 right-0 w-2 h-2 border-t border-r border-[#00f3ff]"></div>
                    <div className="absolute bottom-0 left-0 w-2 h-2 border-b border-l border-[#00f3ff]"></div>
                    <h1 className="font-bold text-xs text-white truncate leading-tight mb-1 font-tech uppercase tracking-wide">{activeBook.title}</h1>
                    <p className="text-[9px] text-zinc-500 truncate font-mono uppercase">{activeBook.author}</p>
                    <div className="mt-2 text-[9px] text-[#00f3ff] font-mono flex items-center gap-1">
                        <Activity size={10} /> SYS.ACTIVE
                    </div>
                </div>
            )}
        </div>
        <div className="flex-1 overflow-y-auto p-0 custom-scrollbar">
          {showLibraryList ? (
             <div className="flex flex-col animate-fade-in">
                {library.map(item => (
                    <button
                        key={item.book.id}
                        onClick={() => {
                            setActiveBookId(item.book.id);
                            if(item.book.chapters.length > 0) setActiveChapterId(item.book.chapters[0].id);
                            setShowLibraryList(false);
                        }}
                        className={`w-full flex items-center gap-3 p-4 border-b border-zinc-900 transition-all group ${
                            activeBookId === item.book.id 
                            ? 'bg-[#00f3ff]/5' 
                            : 'hover:bg-zinc-900'
                        }`}
                    >
                        <div className={`w-1 h-8 ${activeBookId === item.book.id ? 'bg-[#00f3ff]' : 'bg-zinc-800'}`}></div>
                        <div className="text-left min-w-0">
                            <h4 className={`text-[10px] font-bold truncate font-tech uppercase tracking-wide ${activeBookId === item.book.id ? 'text-[#00f3ff]' : 'text-zinc-400'}`}>
                                {item.book.title}
                            </h4>
                            <p className="text-[9px] text-zinc-600 truncate font-mono">{item.book.chapters.length} DATA_BLOCKS</p>
                        </div>
                    </button>
                ))}
             </div>
          ) : (
             <div className="py-2 animate-fade-in">
                {activeBook?.chapters.map((chapter, idx) => {
                    const isBookmarked = activeBook.bookmarks?.includes(chapter.id);
                    return (
                        <div key={chapter.id} className="relative group flex items-center justify-between px-4 py-2 hover:bg-zinc-900/50">
                            <button
                                onClick={() => setActiveChapterId(chapter.id)}
                                className={`flex-1 text-left flex items-center gap-3 border-l-2 py-1 transition-all min-w-0 pr-2 ${
                                    activeChapterId === chapter.id 
                                    ? 'border-[#00f3ff]' 
                                    : 'border-transparent'
                                }`}
                            >
                                <span className={`text-[9px] font-mono w-6 text-right shrink-0 ${activeChapterId === chapter.id ? 'text-[#00f3ff]' : 'text-zinc-700'}`}>
                                    {String(idx + 1).padStart(2, '0')}
                                </span>
                                <div className="min-w-0 flex-1 text-left">
                                    <p className={`font-medium truncate font-tech uppercase tracking-tight text-xs ${activeChapterId === chapter.id ? 'text-white' : 'text-zinc-500'}`}>
                                        {chapter.title}
                                    </p>
                                </div>
                            </button>
                            <button 
                                onClick={(e) => { e.stopPropagation(); toggleBookmark(chapter.id); }}
                                className={`p-1.5 transition-colors shrink-0 ${isBookmarked ? 'text-amber-400' : 'text-zinc-800 hover:text-zinc-500'}`}
                                title={isBookmarked ? "Remove Bookmark" : "Add Bookmark"}
                            >
                                <Tag size={12} fill={isBookmarked ? "currentColor" : "none"} />
                            </button>
                        </div>
                    );
                })}
             </div>
          )}
        </div>
        <div className="p-0 border-t border-zinc-900 bg-black flex flex-col shrink-0">
          <button 
            onClick={() => setShowLibraryList(!showLibraryList)}
            className={`w-full flex items-center justify-between p-4 transition-all text-[10px] font-bold font-tech uppercase tracking-widest border-b border-zinc-900/30 ${
                showLibraryList ? 'text-[#00f3ff] bg-[#00f3ff]/5' : 'text-zinc-500 hover:bg-zinc-900 hover:text-[#00f3ff]'
            }`}
          >
             <div className="flex items-center gap-3">
                <Database size={14} />
                <span>{showLibraryList ? "SESSION_DATA" : "DATA_BANKS"}</span>
             </div>
             <span className={`text-[8px] animate-pulse ${showLibraryList ? 'text-[#00f3ff]' : 'text-zinc-700'}`}>●</span>
          </button>
          <button 
            onClick={() => setIsSettingsOpen(true)}
            className="w-full flex items-center gap-3 p-4 hover:bg-zinc-900 text-zinc-500 hover:text-[#00f3ff] transition-colors text-[10px] font-bold font-tech uppercase tracking-widest"
          >
            <SettingsIcon size={14} />
            <span>SYS_CONFIG</span>
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 relative bg-transparent z-10 text-left">
        <header className="h-14 border-b border-zinc-900 flex items-center justify-between px-4 bg-black/90 backdrop-blur-md sticky top-0 z-30 shrink-0">
          <div className="flex items-center gap-4">
            <button onClick={() => setSidebarOpen(!isSidebarOpen)} className="text-zinc-500 hover:text-[#00f3ff] transition-colors">
              {isSidebarOpen ? <X size={18} /> : <Menu size={18} />}
            </button>
            <div className="h-4 w-[1px] bg-zinc-800 mx-1"></div>
            {activeChapterId ? (
                <div className="flex items-center gap-2">
                    <span className="text-[9px] font-mono text-zinc-600 bg-zinc-900 border border-zinc-800 px-1.5 py-0.5">
                        SEC.{String(activeChapterId || 0).padStart(2, '0')}
                    </span>
                    <ChevronRight size={12} className="text-zinc-700" />
                    <span className="text-xs font-bold text-[#00f3ff] font-tech tracking-wide truncate max-w-[200px]">
                        {activeChapter?.title.toUpperCase()}
                    </span>
                </div>
            ) : (
                <span className="text-xs font-tech text-zinc-500 tracking-widest">AWAITING_INPUT</span>
            )}
          </div>

          <div className="flex items-center bg-zinc-950 border border-zinc-900 p-0.5 rounded-sm">
            {[
              { id: Tab.AUDIOBOOK, icon: Headphones, label: "VOICE_SYNTH" },
              { id: Tab.PODCAST, icon: Mic2, label: "NET_CAST" },
              { id: Tab.CONCEPTS, icon: ImageIcon, label: "VISUAL_CORE" },
              { id: Tab.ANIMATION, icon: Film, label: "CINE_RENDER" },
              { id: Tab.NOTEBOOK, icon: NotebookIcon, label: "MEM_LOG" },
            ].map((tab) => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as Tab)}
                className={`flex items-center justify-center gap-2 w-[120px] py-1.5 transition-all text-[9px] font-bold uppercase tracking-wider font-tech ${
                  activeTab === tab.id 
                    ? 'bg-[#00f3ff]/10 text-[#00f3ff] shadow-[0_0_10px_rgba(0,243,255,0.1)]'
                    : 'text-zinc-600 hover:text-zinc-300 hover:bg-zinc-900'
                }`}
              >
                <tab.icon size={12} className={activeTab === tab.id ? 'text-[#00f3ff]' : ''} />
                <span className="hidden xl:inline">{tab.label}</span>
              </button>
            ))}
          </div>
        </header>

        <div className="flex-1 p-0 overflow-hidden relative">
          <div className="h-full w-full p-2 overflow-y-auto custom-scrollbar">
             {renderContent()}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { NotebookItem, AppSettings } from '../types';
import { Trash2, Quote, Book, Clock, ImageDown, Volume2, CheckSquare, Square, ListChecks, X as XIcon, Play, RefreshCw, Zap, ChevronLeft, ChevronRight, RotateCcw, Notebook as NotebookIcon, ChevronDown, Settings2, Type, Loader2, AlertCircle, ChevronUp, Languages } from 'lucide-react';
import { generateSpeech, batchGetDefinitions, getQuickDefinition, translateText } from '../services/gemini';

interface Props {
  items: NotebookItem[];
  onDelete: (id: string) => void;
  onBulkDelete: (ids: string[]) => void;
  onUpdateComment: (id: string, comment: string) => void;
  onBatchUpdateDefinitions?: (updates: Record<string, string>) => void;
  settings: AppSettings;
}

interface BatchDefinitionUpdate {
  [id: string]: string;
}

type FilterType = 'word' | 'phrase' | 'sentence';

export const Notebook: React.FC<Props> = ({ items, onDelete, onBulkDelete, onUpdateComment, onBatchUpdateDefinitions, settings }) => {
  const fontStyle = { fontFamily: settings.font ? `"${settings.font}", sans-serif` : 'inherit' };
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [activeFilter, setActiveFilter] = useState<FilterType>('word');
  const [isFilterOpen, setIsFilterOpen] = useState(false);

  const [isSelectionMode, setIsSelectionMode] = useState(false);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  const [isFlashcardMode, setIsFlashcardMode] = useState(false);
  const [currentFlashcardIndex, setCurrentFlashcardIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [isPreparingCards, setIsPreparingCards] = useState(false);
  const [fetchingIds, setFetchingIds] = useState<Set<string>>(new Set());

  // Local cache for definitions and translations during the current study session
  const [sessionDefinitions, setSessionDefinitions] = useState<Record<string, string>>({});
  const [sessionTranslations, setSessionTranslations] = useState<Record<string, string>>({});
  const [showTranslatedCard, setShowTranslatedCard] = useState(false);
  const [isTranslatingCard, setIsTranslatingCard] = useState(false);

  const pcmToWav = (base64Pcm: string) => {
    const binaryString = atob(base64Pcm);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, offset: number, str: string) => {
      for (let i = 0; i < str.length; i++) v.setUint8(offset + i, str.charCodeAt(i));
    };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return new Blob([buffer], { type: 'audio/wav' });
  };

  const playPronunciation = async (id: string, text: string) => {
     if (playingId) return;
     setPlayingId(id);
     let audioUrl: string | null = null;
     try {
          const b64 = await generateSpeech(text, "Puck");
          if(b64) {
             const blob = pcmToWav(b64);
             audioUrl = URL.createObjectURL(blob);
             const audio = new Audio(audioUrl);
             audio.onended = () => {
                 setPlayingId(null);
                 if (audioUrl) URL.revokeObjectURL(audioUrl);
             };
             await audio.play();
          } else {
             setPlayingId(null);
          }
      } catch (e) {
          console.error("Playback failed:", e);
          setPlayingId(null);
          if (audioUrl) URL.revokeObjectURL(audioUrl);
      }
  };

  const generateStickyNote = (item: NotebookItem) => {
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) return;
      canvas.width = 800;
      canvas.height = 800;
      ctx.fillStyle = '#050505'; 
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.strokeStyle = '#1f2937';
      ctx.lineWidth = 1;
      for(let i=0; i < canvas.width; i+=40) { ctx.beginPath(); ctx.moveTo(i, 0); ctx.lineTo(i, canvas.height); ctx.stroke(); }
      for(let i=0; i < canvas.height; i+=40) { ctx.beginPath(); ctx.moveTo(0, i); ctx.lineTo(canvas.width, i); ctx.stroke(); }
      const margin = 50;
      const contentWidth = canvas.width - (margin * 2);
      ctx.fillStyle = '#00f3ff';
      const cornerSize = 8;
      ctx.fillRect(margin, margin, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, margin, cornerSize, cornerSize);
      ctx.fillRect(margin, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      let y = margin + 40;
      ctx.fillStyle = '#ff003c';
      ctx.font = 'bold 16px "Courier New", monospace';
      ctx.textAlign = 'left';
      ctx.fillText(`// LOG_DATE: ${new Date(item.timestamp).toISOString().split('T')[0]}`, margin, y);
      y += 25;
      if (item.bookTitle) {
          ctx.fillStyle = '#00f3ff';
          ctx.font = 'bold 20px "Courier New", monospace';
          const authorText = item.bookAuthor ? ` | ${item.bookAuthor}` : '';
          ctx.fillText(`BOOK: ${item.bookTitle.toUpperCase().substring(0, 20)}${authorText.substring(0, 15)}`, margin, y);
          y += 25;
      }
      ctx.strokeStyle = '#334155'; ctx.lineWidth = 1; ctx.beginPath(); ctx.moveTo(margin, y); ctx.lineTo(canvas.width - margin, y); ctx.stroke();
      y += 40;
      let fontSize = 32;
      const mainFont = settings.font ? `"${settings.font}", sans-serif` : 'Georgia';
      ctx.font = `${fontSize}px ${mainFont}`;
      const words = item.text.split(' ');
      let lines: string[] = [];
      let line = '';
      const calculateLines = () => {
         lines = []; line = '';
         for(let n = 0; n < words.length; n++) {
            const testLine = line + words[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
              lines.push(line); line = words[n] + ' ';
            } else { line = testLine; }
         }
         lines.push(line);
      };
      calculateLines();
      const maxHeight = 350;
      while (lines.length * (fontSize * 1.5) > maxHeight && fontSize > 14) {
          fontSize -= 2; ctx.font = `${fontSize}px ${mainFont}`; calculateLines();
      }
      ctx.fillStyle = '#334155'; ctx.font = `${fontSize * 3}px ${mainFont}`;
      ctx.fillText('"', margin - 20, y + fontSize);
      ctx.fillStyle = '#e2e8f0'; ctx.font = `${fontSize}px ${mainFont}`;
      const lineHeight = fontSize * 1.5;
      for (let i = 0; i < lines.length; i++) { ctx.fillText(lines[i], margin, y); y += lineHeight; }
      y += 30;
      if (item.definition) {
          ctx.fillStyle = '#22d3ee'; ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> ANALYSIS_OUTPUT:", margin, y); y += 20;
          ctx.fillStyle = '#94a3b8'; ctx.font = '14px "Courier New", monospace';
          const defWords = item.definition.split(' ');
          let defLine = '';
          for(let n = 0; n < defWords.length; n++) {
            const testLine = defLine + defWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(defLine, margin, y); defLine = defWords[n] + ' '; y += 18;
            } else { defLine = testLine; }
         }
         ctx.fillText(defLine, margin, y); y += 35;
      }
      if (item.comment) {
          ctx.fillStyle = '#f59e0b'; ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> USER_ANNOTATION:", margin, y); y += 20;
          ctx.fillStyle = '#b45309'; ctx.font = 'italic 14px "Courier New", monospace';
          const commentWords = item.comment.split(' ');
          let commentLine = '';
          for(let n = 0; n < commentWords.length; n++) {
            const testLine = commentLine + commentWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(commentLine, margin, y); commentLine = commentWords[n] + ' '; y += 18;
            } else { commentLine = testLine; }
         }
         ctx.fillText(commentLine, margin, y); y += 35;
      }
      ctx.fillStyle = '#1f2937'; ctx.font = '10px "Courier New", monospace'; ctx.textAlign = 'center';
      ctx.fillText("FLASH_NOTES // NEURAL INTERFACE CONTENT", canvas.width / 2, canvas.height - 20);
      const link = document.createElement('a');
      link.download = `flash-note-${item.id}.png`;
      link.href = canvas.toDataURL();
      link.click();
  };

  const filteredItems = items.filter(item => item.type === activeFilter);

  const toggleSelection = (id: string) => {
    const next = new Set(selectedIds);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelectedIds(next);
  };

  const selectAll = () => {
    if (selectedIds.size === filteredItems.length) setSelectedIds(new Set());
    else setSelectedIds(new Set(filteredItems.map(i => i.id)));
  };

  const executeBulkDelete = () => {
      onBulkDelete(Array.from(selectedIds));
      setSelectedIds(new Set());
      setIsSelectionMode(false);
  };

  const startFlashcards = () => {
      if (filteredItems.length === 0) return;
      setCurrentFlashcardIndex(0);
      setIsFlipped(false);
      setShowTranslatedCard(false);
      setIsFlashcardMode(true);
      setSessionDefinitions({});
      setSessionTranslations({});
  };

  const currentStudyItem = filteredItems[currentFlashcardIndex];

  // Logic for switching between original language definition and translation
  const originalDef = (currentStudyItem?.id && sessionDefinitions[currentStudyItem.id]) || currentStudyItem?.definition;
  const translatedDef = currentStudyItem?.id ? sessionTranslations[currentStudyItem.id] : null;
  const activeDefinition = showTranslatedCard ? translatedDef : originalDef;
  const isCurrentItemLoading = currentStudyItem?.id && fetchingIds.has(currentStudyItem.id);

  useEffect(() => {
    if (isFlashcardMode && currentStudyItem && !currentStudyItem.definition && !sessionDefinitions[currentStudyItem.id] && !fetchingIds.has(currentStudyItem.id)) {
        const fetchDef = async () => {
            const itemId = currentStudyItem.id;
            setFetchingIds(prev => new Set(prev).add(itemId));
            try {
                // Always fetch in source language first for Flashcards
                // Note: We only update session cache, NOT the database (removed onBatchUpdateDefinitions)
                const def = await getQuickDefinition(currentStudyItem.text, "the same language as the text");
                setSessionDefinitions(prev => ({ ...prev, [itemId]: def }));
            } catch (e: any) {
                console.error("Failed to pre-fetch definition:", e);
                setSessionDefinitions(prev => ({ ...prev, [itemId]: "ERR_DECODE: Signal interference." }));
            } finally {
                setFetchingIds(prev => {
                    const next = new Set(prev);
                    next.delete(itemId);
                    return next;
                });
            }
        };
        fetchDef();
    }
  }, [isFlashcardMode, currentFlashcardIndex, currentStudyItem]);

  const handleTranslateFlashcard = async (e: React.MouseEvent) => {
      e.stopPropagation();
      if (!currentStudyItem || isTranslatingCard) return;

      if (showTranslatedCard) {
          setShowTranslatedCard(false);
          return;
      }

      if (sessionTranslations[currentStudyItem.id]) {
          setShowTranslatedCard(true);
          return;
      }

      const textToTranslate = originalDef;
      if (!textToTranslate) return;

      setIsTranslatingCard(true);
      try {
          const targetLang = settings.targetLanguage === 'Original' ? 'English' : settings.targetLanguage;
          const trans = await translateText(textToTranslate, targetLang);
          setSessionTranslations(prev => ({ ...prev, [currentStudyItem.id]: trans }));
          setShowTranslatedCard(true);
      } catch (e) {
          console.error("Flashcard translation failed:", e);
      } finally {
          setIsTranslatingCard(false);
      }
  };

  const handleFlip = (item: NotebookItem) => {
      setIsFlipped(!isFlipped);
  };

  const formatAnalysisText = (text: string) => {
      if (!text) return null;
      return text.split('\n').map((line, i) => {
          const trimmed = line.trim();
          if (!trimmed) return <div key={i} className="h-2" />;
          const parts = trimmed.split(/(\*\*.*?\*\*)/g);
          return (
              <p key={i} className="mb-2">
                  {parts.map((part, pi) => {
                      if (part.startsWith('**') && part.endsWith('**')) {
                          return <span key={pi} className="text-[#ff003c] font-bold">{part.slice(2, -2)}</span>;
                      }
                      return part;
                  })}
              </p>
          );
      });
  };

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 text-left relative" style={fontStyle}>
       <style>{`
          .perspective-1000 { perspective: 1000px; -webkit-perspective: 1000px; } 
          .backface-hidden { backface-visibility: hidden; -webkit-backface-visibility: hidden; z-index: 2; } 
          .rotate-y-180 { transform: rotateY(180deg); -webkit-transform: rotateY(180deg); } 
          .transform-style-3d { transform-style: preserve-3d; -webkit-transform-style: preserve-3d; }
          .custom-scrollbar-visible::-webkit-scrollbar { width: 6px; }
          .custom-scrollbar-visible::-webkit-scrollbar-track { background: rgba(0,0,0,0.3); border-radius: 3px; }
          .custom-scrollbar-visible::-webkit-scrollbar-thumb { background: #ff003c; border-radius: 3px; box-shadow: 0 0 10px rgba(255,0,60,0.5); }
          .custom-scrollbar-visible::-webkit-scrollbar-thumb:hover { background: #ff2b5c; }
       `}</style>

       <div className="sticky top-0 z-[160] bg-zinc-950/90 p-3 rounded-lg border border-zinc-800 flex items-center justify-between shadow-[0_4px_20px_rgba(0,0,0,0.6)] backdrop-blur-md mb-4">
           <div className="flex items-center gap-3 border-r border-zinc-800 pr-6">
               <NotebookIcon size={18} className="text-[#00f3ff]" />
               <span className="text-xs font-tech font-bold text-white tracking-[0.2em] uppercase">Mem_Log</span>
           </div>
           <div className="flex items-center gap-3 flex-1 justify-end">
               {!isFlashcardMode && (
                   <>
                       <div className="relative">
                            <button onClick={() => setIsFilterOpen(!isFilterOpen)} className="flex items-center gap-3 px-4 py-1.5 bg-black border border-zinc-800 rounded-sm text-xs font-bold font-mono uppercase text-[#00f3ff] hover:border-[#00f3ff]/50 transition-all min-w-[140px] justify-between group shadow-inner">
                                <span className="flex items-center gap-2"><Settings2 size={14} />{activeFilter}S</span>
                                <ChevronDown size={14} className={`transition-transform duration-300 ${isFilterOpen ? 'rotate-180' : ''}`} />
                            </button>
                            {isFilterOpen && (
                                <div className="absolute top-full left-0 mt-1 w-full bg-[#0a0a0c] border border-zinc-800 shadow-2xl rounded-sm overflow-hidden z-[170] animate-fade-in">
                                    {(['word', 'phrase', 'sentence'] as const).map(f => (
                                        <button key={f} onClick={() => { setActiveFilter(f); setSelectedIds(new Set()); setIsSelectionMode(false); setIsFilterOpen(false); }} className={`w-full text-left px-4 py-3 text-xs font-bold font-mono uppercase transition-colors hover:bg-[#00f3ff]/10 ${activeFilter === f ? 'text-[#00f3ff] bg-[#00f3ff]/5' : 'text-zinc-500 hover:text-zinc-300'}`}>{f}S</button>
                                    ))}
                                </div>
                            )}
                       </div>
                       <button onClick={() => { setIsSelectionMode(!isSelectionMode); setSelectedIds(new Set()); }} className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-bold font-mono uppercase border transition-all min-w-[140px] justify-center ${isSelectionMode ? 'bg-[#ff003c]/10 border-[#ff003c] text-[#ff003c]' : 'bg-zinc-900 border-zinc-800 text-zinc-500 hover:text-white'}`}>{isSelectionMode ? <XIcon size={14} /> : <ListChecks size={14} />}{isSelectionMode ? "EXIT_BATCH" : "BATCH_OPS"}</button>
                   </>
               )}
               <button onClick={isFlashcardMode ? () => setIsFlashcardMode(false) : startFlashcards} disabled={filteredItems.length === 0 || isPreparingCards} className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-black font-mono uppercase transition-all shadow-lg transform active:scale-95 ml-2 min-w-[120px] justify-center ${isFlashcardMode ? 'bg-zinc-800 text-zinc-400 border border-zinc-700 hover:text-white hover:border-white' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc] shadow-[0_0_15px_rgba(0,243,255,0.4)]'}`}>{isFlashcardMode ? <XIcon size={14} /> : (isPreparingCards ? <Loader2 size={14} className="animate-spin" /> : <Play size={14} fill="currentColor" />)}{isFlashcardMode ? "EXIT" : (isPreparingCards ? "SYNCING..." : "INITIATE")}</button>
           </div>
       </div>

       {isFlashcardMode && currentStudyItem ? (
           <div className="absolute inset-0 top-[72px] z-[150] bg-[#020202]/95 flex flex-col items-center justify-center p-6 animate-fade-in font-sans overflow-hidden">
                <div className="w-full max-w-2xl flex flex-col items-center justify-center -mt-8">
                  <div className="text-center mb-8 w-full animate-fade-in-up">
                      <h2 className="text-[#00f3ff] font-tech text-xs uppercase tracking-[0.7em] mb-3 animate-pulse font-black drop-shadow-[0_0_8px_rgba(0,243,255,0.4)]">Neural_Study_Session</h2>
                      <div className="flex items-center justify-center gap-4">
                          <div className="h-[1px] w-12 bg-gradient-to-r from-transparent to-[#00f3ff]/30"></div>
                          <p className="text-zinc-600 font-mono text-[9px] tracking-[0.2em] uppercase">Buffer_Index: {currentFlashcardIndex + 1} / {filteredItems.length}</p>
                          <div className="h-[1px] w-12 bg-gradient-to-l from-transparent to-[#00f3ff]/30"></div>
                      </div>
                  </div>

                  <div onClick={() => handleFlip(currentStudyItem)} className="relative w-full aspect-[16/9] max-h-[400px] perspective-1000 cursor-pointer group mb-10">
                      <div className={`relative w-full h-full transition-transform duration-700 transform-style-3d ${isFlipped ? 'rotate-y-180' : ''}`}>
                          <div className="absolute inset-0 backface-hidden bg-[#050505] border-2 border-[#00f3ff]/20 rounded-2xl flex flex-col items-center justify-center p-10 text-center shadow-[0_0_50px_rgba(0,0,0,1)] hover:border-[#00f3ff]/40 transition-colors overflow-hidden">
                              <div className="absolute top-6 left-6 text-[#00f3ff]/20"><Zap size={32} /></div>
                              <div className="absolute top-6 right-6 text-zinc-800 font-mono text-[8px] tracking-widest uppercase">Front_Layer</div>
                              <p className="text-xl md:text-2xl font-black text-white leading-relaxed font-serif italic max-w-lg">"{currentStudyItem.text}"</p>
                              <div className="absolute bottom-8 flex flex-col items-center gap-1 opacity-40 group-hover:opacity-100 transition-opacity">
                                  <p className="text-cyan-500 font-mono text-[8px] uppercase tracking-widest animate-bounce">Click to Flip_Interface</p>
                              </div>
                          </div>
                          <div className="absolute inset-0 backface-hidden rotate-y-180 bg-[#0a0a0c] border-2 border-[#ff003c]/20 rounded-2xl flex flex-col items-center justify-center p-10 text-center shadow-[0_0_50px_rgba(0,0,0,1)] hover:border-[#ff003c]/40 transition-colors overflow-hidden">
                              <div className="absolute top-6 right-6 flex items-center gap-2">
                                  <button onClick={handleTranslateFlashcard} disabled={isTranslatingCard || isCurrentItemLoading} className={`p-2 rounded-sm border transition-all ${showTranslatedCard ? 'bg-[#ff003c]/10 border-[#ff003c] text-[#ff003c]' : 'bg-zinc-900 border-zinc-800 text-zinc-500 hover:text-white'} ${isTranslatingCard ? 'animate-pulse' : ''}`} title={showTranslatedCard ? "Show Original Analysis" : "Translate Analysis"}>
                                      {isTranslatingCard ? <Loader2 size={12} className="animate-spin" /> : <Languages size={12} />}
                                  </button>
                                  <div className="text-zinc-800 font-mono text-[8px] tracking-widest uppercase">{showTranslatedCard ? 'Translation_Layer' : 'Back_Layer'}</div>
                              </div>
                              <div className="flex flex-col h-full w-full max-w-2xl text-left pt-6 pb-4">
                                  <div className="animate-fade-in flex flex-col h-full overflow-hidden">
                                      <h4 className="text-[#ff003c] font-mono text-[9px] uppercase tracking-[0.4em] mb-4 font-black border-b border-[#ff003c]/20 pb-2 shrink-0">{showTranslatedCard ? 'Translation_Output' : 'Analysis_Output'}:</h4>
                                      <div className="flex-1 overflow-hidden relative group/scroll flex">
                                          <div className="flex-1 overflow-y-auto custom-scrollbar-visible pr-4 font-mono text-sm leading-relaxed text-zinc-200 bg-black/40 p-4 rounded border border-zinc-900 shadow-inner">
                                              {isCurrentItemLoading || isTranslatingCard ? (
                                                  <div className="flex items-center gap-3 text-zinc-600 py-4">
                                                      <Loader2 size={16} className="animate-spin text-[#ff003c]" />
                                                      DECODING_DATA...
                                                  </div>
                                              ) : activeDefinition?.includes("ERR_500") ? (
                                                  <div className="bg-rose-950/20 border border-rose-900/50 p-4 rounded flex items-start gap-3">
                                                      <AlertCircle size={18} className="text-[#ff003c] shrink-0 mt-1" />
                                                      <div>
                                                          <p className="text-rose-400 font-mono text-xs uppercase font-bold mb-1">Signal Interrupt</p>
                                                          <p className="text-xs text-rose-500/80 font-mono leading-tight">{activeDefinition}</p>
                                                      </div>
                                                  </div>
                                              ) : (
                                                  <div className="animate-fade-in">
                                                      {formatAnalysisText(activeDefinition || "DATA_LINK_OFFLINE: Analysis unavailable.")}
                                                  </div>
                                              )}
                                              {currentStudyItem.comment && (
                                                  <div className="pt-4 mt-4 border-t border-zinc-800/50 animate-fade-in">
                                                      <h4 className="text-amber-500 font-mono text-[9px] uppercase tracking-[0.4em] mb-2 font-black">User_Annotation:</h4>
                                                      <p className="text-xs text-zinc-500 italic leading-relaxed">"{currentStudyItem.comment}"</p>
                                                  </div>
                                              )}
                                          </div>
                                          {!isCurrentItemLoading && (
                                              <div className="w-8 flex flex-col items-center justify-between py-2 border-l border-zinc-900 ml-2 shrink-0 opacity-40 hover:opacity-100 transition-opacity">
                                                  <div className="flex flex-col items-center gap-1"><ChevronUp size={14} className="text-[#ff003c]" /><div className="h-4 w-[1px] bg-[#ff003c]/30" /></div>
                                                  <span className="[writing-mode:vertical-lr] text-[8px] font-mono text-zinc-600 uppercase tracking-widest">Scroll_Data</span>
                                                  <div className="flex flex-col items-center gap-1"><div className="h-4 w-[1px] bg-[#ff003c]/30" /><ChevronDown size={14} className="text-[#ff003c]" /></div>
                                              </div>
                                          )}
                                      </div>
                                  </div>
                              </div>
                              <p className="absolute bottom-4 left-1/2 -translate-x-1/2 text-zinc-700 font-mono text-[8px] uppercase tracking-widest pointer-events-none">Return to Snippet_View</p>
                          </div>
                      </div>
                  </div>
                  <div className="flex items-center gap-16 animate-fade-in-up" style={{ animationDelay: '0.2s' }}>
                      <button onClick={(e) => { e.stopPropagation(); setIsFlipped(false); setShowTranslatedCard(false); setCurrentFlashcardIndex((prev) => (prev - 1 + filteredItems.length) % filteredItems.length); }} className="group flex flex-col items-center gap-2">
                         <div className="p-4 bg-zinc-900 border border-zinc-800 text-zinc-500 group-hover:text-[#00f3ff] group-hover:border-[#00f3ff] rounded-full transition-all group-hover:scale-110 shadow-lg"><ChevronLeft size={28} /></div>
                         <span className="text-[8px] font-mono text-zinc-700 group-hover:text-zinc-500 uppercase tracking-widest">Previous</span>
                      </button>
                      <button onClick={(e) => { e.stopPropagation(); setIsFlipped(false); setShowTranslatedCard(false); setCurrentFlashcardIndex((prev) => (prev + 1) % filteredItems.length); }} className="group flex flex-col items-center gap-2">
                         <div className="p-4 bg-zinc-900 border border-zinc-800 text-zinc-500 group-hover:text-[#00f3ff] group-hover:border-[#00f3ff] rounded-full transition-all group-hover:scale-110 shadow-lg"><ChevronRight size={28} /></div>
                         <span className="text-[8px] font-mono text-zinc-700 group-hover:text-zinc-500 uppercase tracking-widest">Next</span>
                      </button>
                  </div>
              </div>
           </div>
       ) : (
           <>
               {isSelectionMode && (
                 <div className="mb-4 bg-[#ff003c]/5 border border-[#ff003c]/20 p-2 pr-3 rounded flex items-center justify-between animate-fade-in shrink-0">
                     <div className="flex items-center gap-4">
                         <button onClick={selectAll} className="flex items-center gap-2 text-xs font-mono font-bold text-zinc-400 hover:text-white px-2 py-1 rounded hover:bg-zinc-800 transition-colors">
                             {selectedIds.size === filteredItems.length && filteredItems.length > 0 ? <CheckSquare size={14} className="text-[#ff003c]" /> : <Square size={14} />}
                             SELECT_ALL
                         </button>
                         <span className="text-[10px] font-mono text-[#ff003c] bg-[#ff003c]/10 px-2 py-0.5 rounded uppercase">{selectedIds.size} SNIPPETS_TARGETED</span>
                     </div>
                     <button onClick={executeBulkDelete} disabled={selectedIds.size === 0} className="flex items-center gap-2 px-4 py-1.5 bg-[#ff003c] text-white hover:bg-rose-600 rounded-sm text-xs font-mono font-bold uppercase disabled:opacity-30 disabled:cursor-not-allowed transition-all shadow-[0_0_15px_rgba(255,0,60,0.3)] min-w-[120px] justify-center"><Trash2 size={12} /> PURGE</button>
                 </div>
               )}
               {items.length === 0 ? (
                   <div className="flex-1 flex flex-col items-center justify-center text-zinc-600 font-mono gap-4 animate-fade-in"><Book size={48} className="opacity-20" /><p className="text-sm">NO_DATA_LOGGED</p><p className="text-[10px] text-zinc-700 max-w-xs text-center uppercase tracking-widest">Right-click text selection in reader to populate your lexicon.</p></div>
               ) : filteredItems.length === 0 ? (
                   <div className="flex-1 flex flex-col items-center justify-center text-zinc-700 font-mono gap-2 animate-fade-in"><p className="text-xs uppercase tracking-widest opacity-50">BUFFER_EMPTY_FOR_{activeFilter.toUpperCase()}S</p></div>
               ) : (
                   <div className="flex-1 overflow-y-auto pr-2 pb-10 custom-scrollbar space-y-4">
                       {filteredItems.map((item, idx) => {
                           const isSelected = selectedIds.has(item.id);
                           const typeColor = item.type === 'phrase' ? 'text-[#ff003c]' : item.type === 'word' ? 'text-cyan-400' : 'text-[#00f3ff]';
                           return (
                           <div key={item.id} className={`bg-[#0a0a0c] border rounded-lg p-5 relative group transition-all animate-fade-in-up pr-14 ${isSelected ? 'border-[#ff003c]' : 'border-zinc-800 hover:border-zinc-700'}`} style={{ animationDelay: `${idx * 0.05}s` }}>
                               {isSelectionMode && (
                                   <div onClick={() => toggleSelection(item.id)} className="absolute inset-y-0 left-0 w-12 flex items-center justify-center z-30 cursor-pointer bg-gradient-to-r from-black/80 to-transparent">
                                       {isSelected ? <CheckSquare size={20} className="text-[#ff003c]" /> : <Square size={20} className="text-zinc-600 hover:text-zinc-400" />}
                                   </div>
                               )}
                               <div className="absolute top-2 right-2 flex flex-col gap-1 z-20">
                                   <button onClick={() => playPronunciation(item.id, item.text)} disabled={!!playingId} className={`p-1.5 rounded border border-transparent transition-all mb-1 ${playingId === item.id ? 'text-[#00f3ff] bg-[#00f3ff]/10 animate-pulse' : 'text-zinc-600 hover:text-[#00f3ff] bg-zinc-900/50 hover:bg-[#00f3ff]/10'}`} title="Pronounce"><Volume2 size={14} /></button>
                                   <button onClick={() => generateStickyNote(item)} className="p-1.5 text-zinc-600 hover:text-[#00f3ff] bg-zinc-900/50 hover:bg-[#00f3ff]/10 rounded border border-transparent hover:border-[#00f3ff]/20 transition-all" title="Generate Visual Log"><ImageDown size={14} /></button>
                                   <button onClick={() => onDelete(item.id)} disabled={isSelectionMode} className={`p-1.5 text-zinc-600 hover:text-[#ff003c] bg-zinc-900/50 hover:bg-[#ff003c]/10 rounded border border-transparent hover:border-[#ff003c]/20 transition-all ${isSelectionMode ? 'opacity-20 cursor-not-allowed' : ''}`} title="Purge Entry"><Trash2 size={14} /></button>
                               </div>
                               <div className={`flex items-start gap-4 ${isSelectionMode ? 'pl-8 transition-all' : ''}`}>
                                   <div className="mt-1 shrink-0">{item.type === 'sentence' ? <Quote size={16} className="text-[#00f3ff]" /> : item.type === 'phrase' ? <Zap size={16} className="text-[#ff003c]" /> : <Type size={16} className="text-cyan-400" />}</div>
                                   <div className="flex-1 min-w-0 space-y-3">
                                       <div><p className={`text-white text-base font-medium leading-relaxed font-serif break-words ${isSelected ? 'text-[#ff003c]' : ''}`}>"{item.text}"</p>
                                           <div className="flex items-center gap-3 mt-2 flex-wrap">
                                               <span className={`text-[9px] font-mono uppercase tracking-wide bg-zinc-900 px-1.5 py-0.5 rounded border border-zinc-800 ${typeColor}`}>{item.type}</span>
                                               {item.bookTitle && <span className="text-[10px] font-mono text-cyan-500/60 truncate max-w-[150px]">{item.bookTitle}</span>}
                                               {item.sourceChapter && <span className="text-[10px] font-mono text-zinc-600 truncate max-w-[200px]">CH: {item.sourceChapter}</span>}
                                               <span className="text-[10px] font-mono text-zinc-700 flex items-center gap-1"><Clock size={10} />{new Date(item.timestamp).toLocaleDateString()}</span>
                                           </div>
                                       </div>
                                       {item.definition && (
                                           <div className="bg-black/50 p-3 rounded border border-zinc-900"><p className="text-sm text-zinc-500 italic font-mono leading-relaxed">{item.definition}</p></div>
                                       )}
                                       <div className="mt-2"><textarea placeholder="Add neural annotations..." value={item.comment || ''} onChange={(e) => onUpdateComment(item.id, e.target.value)} className="w-full bg-[#050505] border border-zinc-800 rounded p-2 text-xs text-zinc-400 focus:border-[#00f3ff] focus:outline-none transition-colors min-h-[50px] font-mono" /></div>
                                   </div>
                               </div>
                           </div>
                           );
                       })}
                   </div>
               )}
           </>
       )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Film, Download, RotateCcw, Settings2, MonitorPlay, Globe, Square, RefreshCw, Play, Pause, RotateCw, Volume2, VolumeX, Maximize2, Minimize2, Gauge } from 'lucide-react';
import { Chapter, FileContext } from '../types';
import { generateSummaryVideo, hasValidKeyForVeo, requestVeoKey } from '../services/gemini';
import { Loader } from './ui/Loader';

interface Props {
  chapter: Chapter;
  fileContext: FileContext;
}

const STYLES = [
  'Cinematic', 'Anime', 'Photorealistic', 'Cartoon', 'Cyberpunk', 
  'Vaporwave', 'Noir', 'Documentary', 'Surreal'
];

const LANGUAGES = [
  'Original', 'Arabic', 'Chinese (Simplified)', 'Chinese (Traditional)', 'Dutch', 'English', 'French', 'German', 'Hindi', 'Indonesian', 'Italian', 'Japanese', 'Korean', 'Polish', 'Portuguese', 'Russian', 'Spanish', 'Swedish', 'Thai', 'Turkish', 'Vietnamese'
];

const RESOLUTIONS: ('720p' | '1080p' | '4K')[] = ['720p', '1080p', '4K'];
const SPEEDS = [0.5, 0.75, 1.0, 1.25, 1.5, 2.0];

export const VideoSummary: React.FC<Props> = ({ chapter, fileContext }) => {
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [status, setStatus] = useState<string>("");
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedStyle, setSelectedStyle] = useState('Cinematic');
  const [selectedLanguage, setSelectedLanguage] = useState('Original');
  const [selectedResolution, setSelectedResolution] = useState<'720p' | '1080p' | '4K'>('720p');

  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [playbackRate, setPlaybackRate] = useState(1.0);
  const [isMuted, setIsMuted] = useState(false);
  const [isFullScreen, setIsFullScreen] = useState(false);
  const [playbackProgress, setPlaybackProgress] = useState(0);
  const [controlsVisible, setControlsVisible] = useState(true);

  const abortRef = useRef<boolean>(false);
  const videoRef = useRef<HTMLVideoElement | null>(null);
  const containerRef = useRef<HTMLDivElement | null>(null);
  const controlsTimeoutRef = useRef<number | null>(null);

  useEffect(() => {
    return () => {
      if (videoUrl) URL.revokeObjectURL(videoUrl);
    };
  }, [videoUrl]);

  const handleToggleGeneration = async () => {
    if (isGenerating) {
        abortRef.current = true;
        setIsGenerating(false);
        setStatus("");
        return;
    }
    setError(null);
    setIsGenerating(true);
    abortRef.current = false;
    setStatus("Authenticating & Generating...");
    try {
      const hasKey = await hasValidKeyForVeo();
      if (!hasKey) {
        setStatus("Waiting for Access Key...");
        await requestVeoKey();
      }
      if (abortRef.current) return;

      const targetLang = selectedLanguage === 'Original' ? 'the source language of the document' : selectedLanguage;
      const url = await generateSummaryVideo(
        fileContext, 
        chapter, 
        setStatus, 
        selectedStyle, 
        targetLang,
        selectedResolution === '4K' ? '1080p' : selectedResolution as any
      );

      if (!abortRef.current) {
        if (videoUrl) URL.revokeObjectURL(videoUrl);
        setVideoUrl(url);
        setIsPlaying(false);
      }
    } catch (e: any) {
      if (!abortRef.current) {
        console.error(e);
        let msg = "Generation failed.";
        if (e.message?.includes("Requested entity was not found")) {
            msg = "Key Invalid. Paid project key required.";
            await requestVeoKey();
        } else if (e.message) msg = e.message;
        setError(msg);
      }
    } finally {
      if (!abortRef.current) {
        setIsGenerating(false);
        setStatus("");
      }
    }
  };

  const togglePlay = async (e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (!videoRef.current || !videoUrl) return;

    try {
      if (isPlaying) {
        videoRef.current.pause();
        setIsPlaying(false);
      } else {
        const playPromise = videoRef.current.play();
        if (playPromise !== undefined) {
          await playPromise;
          setIsPlaying(true);
        }
      }
    } catch (err) {
      console.warn("Playback interrupted or failed:", err);
      setIsPlaying(false);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = parseFloat(e.target.value);
    if (videoRef.current && duration) {
       videoRef.current.currentTime = (val / 100) * duration;
    }
  };

  const toggleMute = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (videoRef.current) {
        videoRef.current.muted = !isMuted;
        setIsMuted(!isMuted);
    }
  };

  const toggleFullScreen = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!containerRef.current) return;
    if (!document.fullscreenElement) {
        containerRef.current.requestFullscreen().catch(err => {
            console.error(`Error attempting to enable full-screen mode: ${err.message}`);
        });
    } else {
        document.exitFullscreen();
    }
  };

  const resetControlsTimeout = () => {
    setControlsVisible(true);
    if (controlsTimeoutRef.current) {
      window.clearTimeout(controlsTimeoutRef.current);
    }
    if (isPlaying) {
      controlsTimeoutRef.current = window.setTimeout(() => {
        setControlsVisible(false);
      }, 3000);
    }
  };

  useEffect(() => {
    const handleFsChange = () => {
      const isFs = !!document.fullscreenElement;
      setIsFullScreen(isFs);
      if (!isFs) setControlsVisible(true);
    };
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const formatTime = (seconds: number): string => {
    if (!seconds || isNaN(seconds)) return "00:00";
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const updateProgress = () => {
    if (videoRef.current) {
        setCurrentTime(videoRef.current.currentTime);
        setDuration(videoRef.current.duration || 0);
        setPlaybackProgress((videoRef.current.currentTime / (videoRef.current.duration || 1)) * 100);
    }
  };

  useEffect(() => {
    if (videoRef.current) {
        videoRef.current.playbackRate = playbackRate;
    }
  }, [playbackRate, videoUrl]);

  const currentStatusLabel = isGenerating ? "STOP" : videoUrl ? "REGENERATE" : "INITIATE";
  const currentStatusIcon = isGenerating ? <Square size={14} fill="currentColor" /> : videoUrl ? <RefreshCw size={14} /> : <Play size={14} fill="currentColor" />;

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 text-left overflow-hidden">
      {/* Top Controls Bar */}
      <div className="bg-zinc-950/80 p-3 rounded-lg border border-cyan-900/40 mb-3 flex items-center justify-between shrink-0 shadow-[0_0_15px_rgba(0,243,255,0.05)] w-full flex-wrap gap-2 z-20">
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono text-xs">
                 <MonitorPlay size={18} className="text-[#00f3ff]" />
                 <span>Cine_Render</span>
              </div>
          </div>
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                 <div className="p-1.5 text-zinc-500"><Settings2 size={16} /></div>
                 <select value={selectedStyle} onChange={(e) => setSelectedStyle(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]">{STYLES.map(t => <option key={t} value={t}>{t}</option>)}</select>
                 <div className="w-[1px] h-4 bg-zinc-700"></div>
                 <div className="p-1.5 text-zinc-500"><Maximize2 size={16} /></div>
                 <select value={selectedResolution} onChange={(e) => setSelectedResolution(e.target.value as any)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]">{RESOLUTIONS.map(res => <option key={res} value={res}>{res}</option>)}</select>
              </div>
              <button onClick={handleToggleGeneration} className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-bold font-mono uppercase transition-all shadow-[0_0_10px_rgba(0,243,255,0.3)] min-w-[120px] justify-center ${isGenerating ? 'bg-[#ff003c] text-white hover:bg-rose-600' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc]'}`}>
                {currentStatusIcon}
                {currentStatusLabel}
              </button>
          </div>
      </div>

      {/* Main Content Area - Player height synced to auto-fix window */}
      <div className="flex-1 flex flex-col items-center justify-start relative min-h-0 bg-[#020202] rounded-lg border border-zinc-900 shadow-inner overflow-hidden">
        <div className="absolute inset-0 bg-grid opacity-[0.05] pointer-events-none"></div>

        {/* The Player Container - Auto height */}
        <div 
          ref={containerRef} 
          onMouseMove={resetControlsTimeout}
          className="relative w-full h-full flex flex-col bg-black shadow-2xl transition-all duration-500 group overflow-hidden shrink-0"
        >
            {/* Visual Screen */}
            <div className="flex-1 relative flex items-center justify-center overflow-hidden border-b border-zinc-900" onClick={() => videoUrl && togglePlay()}>
                {!videoUrl && !isGenerating && (
                    <div className="z-10 text-center space-y-4 p-8">
                        <div className="w-16 h-16 bg-zinc-900/50 rounded-full flex items-center justify-center mx-auto border border-zinc-800">
                             <Film className="text-zinc-700 w-6 h-6" />
                        </div>
                        <p className="text-zinc-600 font-mono text-[10px] uppercase tracking-widest">Awaiting Render Signal</p>
                        {error && <p className="text-[#ff003c] text-[9px] font-mono mt-2 border border-[#ff003c]/20 p-2 bg-[#ff003c]/5">ERROR: {error}</p>}
                    </div>
                )}

                {isGenerating && (
                    <div className="z-20 scale-75">
                         <Loader text={status} />
                    </div>
                )}

                {videoUrl && !isGenerating && (
                    <>
                        <video 
                            key={videoUrl}
                            ref={videoRef}
                            src={videoUrl ? `${videoUrl}#t=0.001` : undefined}
                            onTimeUpdate={updateProgress}
                            onLoadedMetadata={updateProgress}
                            onPlay={() => { 
                                setIsPlaying(true);
                                if(videoRef.current) videoRef.current.playbackRate = playbackRate;
                            }}
                            onPause={() => setIsPlaying(false)}
                            className="w-full h-full object-contain pointer-events-none"
                            playsInline
                        />
                        <div className={`absolute top-3 left-3 z-30 flex gap-2 transition-opacity duration-500 ${controlsVisible ? 'opacity-100' : 'opacity-0'}`}>
                             <div className="bg-black/60 backdrop-blur-md px-2 py-0.5 border border-cyan-500/30 rounded-sm text-[8px] font-mono text-cyan-400 uppercase tracking-widest">Live_Playback</div>
                             <div className="bg-black/60 backdrop-blur-md px-2 py-0.5 border border-zinc-800 rounded-sm text-[8px] font-mono text-zinc-500 uppercase tracking-widest">{selectedResolution}</div>
                        </div>
                    </>
                )}
            </div>

            {/* Control Bar - Matched to Net_Cast Spec */}
            <div className={`w-full bg-[#020202] relative z-40 shrink-0 transition-all duration-500 ${videoUrl && controlsVisible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-full pointer-events-none'}`}>
                {/* Progress Bar (Absolute Top of Control Bar) */}
                <div className="absolute top-0 left-0 w-full h-1 bg-zinc-800 hover:h-2 transition-all cursor-pointer z-50 group/progress">
                    <input 
                        type="range" 
                        min="0" max="100" step="0.1" 
                        value={playbackProgress} 
                        onChange={handleSeek} 
                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                    />
                    <div className="h-full bg-cyan-500 relative pointer-events-none" style={{ width: `${playbackProgress}%` }}>
                        <div className="absolute right-0 top-1/2 -translate-y-1/2 w-3 h-3 bg-cyan-100 rounded-full shadow-[0_0_10px_#00f3ff] opacity-0 group-hover/progress:opacity-100 transition-opacity"></div>
                    </div>
                </div>

                <div className="flex items-center justify-between p-3">
                    {/* Speed Controls (flex-1) */}
                    <div className="flex-1 flex items-center gap-2">
                        {SPEEDS.map(s => (
                            <button 
                                key={s} 
                                onClick={(e) => { e.stopPropagation(); setPlaybackRate(s); }} 
                                className={`text-[10px] font-mono font-bold transition-all ${playbackRate === s ? 'text-cyan-400' : 'text-zinc-600 hover:text-zinc-400'}`}
                            >
                                {s}x
                            </button>
                        ))}
                    </div>

                    {/* Primary Transport (flex-2) */}
                    <div className="flex-2 flex items-center justify-center gap-6">
                        <button onClick={(e) => { e.stopPropagation(); if(videoRef.current) videoRef.current.currentTime -= 5; }} className="text-zinc-500 hover:text-cyan-400 transition-colors"><RotateCcw size={20} /></button>
                        <button onClick={togglePlay} className={`w-10 h-10 rounded-full flex items-center justify-center transition-all ${isPlaying ? 'bg-transparent border-2 border-[#00f3ff] text-[#00f3ff] shadow-[0_0_15px_rgba(0,243,255,0.3)]' : 'bg-[#00f3ff] border-[#00f3ff] text-black shadow-[0_0_20px_rgba(0,243,255,0.6)] hover:scale-105'}`}>
                            {isPlaying ? <Pause size={18} fill="currentColor" /> : <Play size={18} fill="currentColor" className="ml-1" />}
                        </button>
                        <button onClick={(e) => { e.stopPropagation(); if(videoRef.current) videoRef.current.currentTime += 5; }} className="text-zinc-500 hover:text-cyan-400 transition-colors"><RotateCw size={20} /></button>
                    </div>

                    {/* Secondary Controls (flex-1) */}
                    <div className="flex-1 flex items-center justify-end gap-3">
                        <span className="text-[10px] font-mono text-zinc-600 min-w-[70px] text-right">{formatTime(currentTime)} / {formatTime(duration)}</span>
                        <button onClick={toggleMute} className="text-zinc-600 hover:text-cyan-400 transition-colors">
                            {isMuted ? <VolumeX size={18} /> : <Volume2 size={18} />}
                        </button>
                        <a href={videoUrl || '#'} download={`cine-render-${chapter.id}.mp4`} onClick={(e) => e.stopPropagation()} className="text-zinc-600 hover:text-cyan-400 transition-colors">
                            <Download size={18} />
                        </a>
                        <button onClick={toggleFullScreen} className="text-zinc-600 hover:text-cyan-400 transition-colors">
                            {isFullScreen ? <Minimize2 size={18} /> : <Maximize2 size={18} />}
                        </button>
                    </div>
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Lightbulb, Image as ImageIcon, Download, RefreshCw, Settings2, Hexagon, Globe, Archive, PlayCircle, Play, Square, Maximize } from 'lucide-react';
import { Concept, Chapter, FileContext } from '../types';
import { extractConcepts, generateConceptImage } from '../services/gemini';
import { Loader } from './ui/Loader';
import JSZip from 'jszip';

interface Props {
  chapter: Chapter;
  fileContext: FileContext;
}

const STYLES = [
  'Digital Art', 'Cinematic', 'Anime', 'Photorealistic', 'Cartoon', 'Sketch', 
  'Cyberpunk', 'Vaporwave', 'Neon', 'Line Art', 'Low Poly', 'Isometric',
  '3D Render', 'Pixel Art'
];
const RATIOS = ['1:1', '16:9', '4:3', '9:16', '3:4', '2:3'];

export const Visualizer: React.FC<Props> = ({ chapter, fileContext }) => {
  const [concepts, setConcepts] = useState<Concept[]>([]);
  const [images, setImages] = useState<Record<string, string>>({});
  const [loadingImages, setLoadingImages] = useState<Record<string, boolean>>({});
  const [isInitializing, setIsInitializing] = useState(false);
  const [isGeneratingAll, setIsGeneratingAll] = useState(false);
  const [hasInitiated, setHasInitiated] = useState(false);

  const [selectedStyle, setSelectedStyle] = useState('Cyberpunk');
  const [selectedRatio, setSelectedRatio] = useState('1:1');

  const abortRef = useRef<boolean>(false);

  useEffect(() => {
    let mounted = true;
    const loadConcepts = async () => {
      setIsInitializing(true);
      try {
        const extracted = await extractConcepts(fileContext, chapter);
        if (mounted) setConcepts(extracted);
      } catch (err) {
        console.error(err);
      } finally {
        if (mounted) setIsInitializing(false);
      }
    };
    loadConcepts();
    return () => { mounted = false; };
  }, [chapter, fileContext]);

  const handleGenerateImage = async (concept: Concept, forceRegenerate = false) => {
    if (loadingImages[concept.term] && !forceRegenerate) return;
    setLoadingImages(prev => ({ ...prev, [concept.term]: true }));
    try {
      const imgUrl = await generateConceptImage(concept.visualPrompt, selectedStyle, selectedRatio);
      setImages(prev => ({ ...prev, [concept.term]: imgUrl }));
    } catch (e) {
      console.error("Image gen failed", e);
    } finally {
      setLoadingImages(prev => ({ ...prev, [concept.term]: false }));
    }
  };

  const handleToggleInitiate = async () => {
    if (isGeneratingAll) {
      abortRef.current = true;
      setIsGeneratingAll(false);
      return;
    }
    setIsGeneratingAll(true);
    setHasInitiated(true);
    abortRef.current = false;
    const pendingConcepts = concepts.filter(c => !images[c.term]);
    const targets = pendingConcepts.length > 0 ? pendingConcepts : concepts;
    for (let i = 0; i < targets.length; i++) {
        if (abortRef.current) break;
        const concept = targets[i];
        await handleGenerateImage(concept, pendingConcepts.length === 0);
        await new Promise(resolve => setTimeout(resolve, 500));
    }
    setIsGeneratingAll(false);
  };

  const allImagesGenerated = concepts.length > 0 && concepts.every(c => images[c.term]);
  const renderButtonLabel = () => {
