                                    <a href={images[currentConcept.term]} download={`lumina-concept-${currentConcept.term}.png`} className="p-3 bg-zinc-900 text-cyan-400 rounded-lg hover:bg-cyan-500 hover:text-black transition-all border border-cyan-500/30 hover:scale-105 shadow-lg" title="Download"><Download size={24} /></a>
                                    <button onClick={() => handleGenerateImage(currentConcept, true)} className="p-3 bg-zinc-900 text-[#ff003c] rounded-lg hover:bg-[#ff003c] hover:text-white transition-all border border-[#ff003c]/30 hover:scale-105 shadow-lg" title="Regenerate"><RefreshCw size={24} /></button>
                                </div>
