import React, { useState, useEffect, useRef } from 'react';
import { Book, Copy, Search, Loader2, BookOpen, FilePlus, Volume2, Languages } from 'lucide-react';
import { getQuickDefinition, generateSpeech, translateText } from '../services/gemini';
import { NotebookItem } from '../types';

interface Props {
  onAddToNotebook: (item: Omit<NotebookItem, 'id' | 'timestamp'>) => void;
  activeLanguage: string;
}

interface ContextMenuState {
  visible: boolean;
  x: number;
  y: number;
  text: string;
  source: string; // New field for context source
}

interface DefinitionState {
  visible: boolean;
  loading: boolean;
  text: string | null;
  originalText: string | null;
  translatedText: string | null;
  isTranslated: boolean;
  position: { x: number; y: number };
}

export const GlobalContextLayer: React.FC<Props> = ({ onAddToNotebook, activeLanguage }) => {
  const [menu, setMenu] = useState<ContextMenuState>({ visible: false, x: 0, y: 0, text: '', source: 'Input_Stream' });
  const [definition, setDefinition] = useState<DefinitionState>({ 
      visible: false, 
      loading: false, 
      text: null, 
      originalText: null,
      translatedText: null,
      isTranslated: false,
      position: { x: 0, y: 0 } 
  });
  const [isPlaying, setIsPlaying] = useState(false);
  const [isTranslating, setIsTranslating] = useState(false);

  const menuRef = useRef<HTMLDivElement>(null);
  const defRef = useRef<HTMLDivElement>(null);

  const pcmToWav = (base64Pcm: string) => {
    const binaryString = atob(base64Pcm);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, offset: number, str: string) => {
      for (let i = 0; i < str.length; i++) v.setUint8(offset + i, str.charCodeAt(i));
    };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 24000 * 2, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return new Blob([buffer], { type: 'audio/wav' });
  };

  useEffect(() => {
    const handleContextMenu = (e: MouseEvent) => {
      const selection = window.getSelection();
      const text = selection?.toString().trim();

      if (text && text.length > 0) {
        e.preventDefault();
        let x = e.clientX;
        let y = e.clientY;
        if (x + 200 > window.innerWidth) x = window.innerWidth - 210;
        if (y + 150 > window.innerHeight) y = window.innerHeight - 160;

        let source = "Input_Stream";
        let node = selection.anchorNode;
        while(node && node !== document.body) {
            if (node instanceof Element && node.getAttribute('data-source')) {
                source = node.getAttribute('data-source') || "Input_Stream";
                break;
            }
            node = node.parentElement;
        }

        setMenu({ visible: true, x, y, text, source });
        setDefinition(prev => ({ ...prev, visible: false }));
      }
    };

    const handleClick = (e: MouseEvent) => {
      if (menu.visible && menuRef.current && !menuRef.current.contains(e.target as Node)) {
        setMenu(prev => ({ ...prev, visible: false }));
      }
      if (definition.visible && defRef.current && !defRef.current.contains(e.target as Node)) {
          setDefinition(prev => ({ ...prev, visible: false }));
      }
    };

    document.addEventListener('contextmenu', handleContextMenu);
    document.addEventListener('mousedown', handleClick);
    return () => {
      document.removeEventListener('contextmenu', handleContextMenu);
      document.removeEventListener('mousedown', handleClick);
    };
  }, [menu.visible, definition.visible]);

  const handleDefine = async (e: React.MouseEvent) => {
    e.stopPropagation();
    e.nativeEvent.stopImmediatePropagation();

    setDefinition({ 
        visible: true, 
        loading: true, 
        text: null, 
        originalText: null,
        translatedText: null,
        isTranslated: false,
        position: { x: menu.x, y: menu.y } 
    });
    setMenu(prev => ({ ...prev, visible: false }));

    try {
        // Fetch definition in its source language as per requirements
        const def = await getQuickDefinition(menu.text, "the same language as the provided text");
        setDefinition(prev => ({ 
            ...prev, 
            loading: false, 
            text: def,
            originalText: def 
        }));
    } catch (e) {
        setDefinition(prev => ({ ...prev, loading: false, text: "Could not retrieve definition." }));
    }
  };

  const handleTranslateToggle = async () => {
      if (isTranslating || definition.loading || !definition.originalText) return;

      if (definition.isTranslated) {
           setDefinition(prev => ({
              ...prev,
              text: prev.originalText,
              isTranslated: false
          }));
      } else {
          if (definition.translatedText) {
              setDefinition(prev => ({
                  ...prev,
                  text: prev.translatedText,
                  isTranslated: true
              }));
          } else {
              setIsTranslating(true);
              setDefinition(prev => ({ ...prev, loading: true }));
              try {
                  const targetLang = activeLanguage === 'Original' ? 'English' : activeLanguage;
                  const trans = await translateText(definition.originalText, targetLang);
                  setDefinition(prev => ({ 
                      ...prev, 
                      loading: false, 
                      text: trans,
                      translatedText: trans,
                      isTranslated: true
                  }));
              } catch(e) {
                  setDefinition(prev => ({ ...prev, loading: false }));
              } finally {
                  setIsTranslating(false);
              }
          }
      }
  };

  const handlePronounce = async () => {
      if (isPlaying || !menu.text) return;
      setIsPlaying(true);
      let audioUrl: string | null = null;
      try {
          const b64 = await generateSpeech(menu.text, "Puck");
          if(b64) {
             const blob = pcmToWav(b64);
             audioUrl = URL.createObjectURL(blob);
             const audio = new Audio(audioUrl);
             audio.onended = () => {
                 setIsPlaying(false);
                 if (audioUrl) URL.revokeObjectURL(audioUrl);
             };
             await audio.play();
          } else {
             setIsPlaying(false);
          }
      } catch (e) {
          console.error(e);
          setIsPlaying(false);
          if (audioUrl) URL.revokeObjectURL(audioUrl);
      }
  };

  const handleAddToNotebook = () => {
     // Default add: NO definition included
     onAddToNotebook({
         text: menu.text,
         type: menu.text.includes(' ') && menu.text.length > 30 ? 'sentence' : 'word',
         definition: undefined,
         contextSource: menu.source
     });
     setMenu(prev => ({ ...prev, visible: false }));
  };

  const handleSaveWithDefinition = () => {
      // Save WITH definition: captures the currently visible text (original or translated)
      onAddToNotebook({
         text: menu.text,
         type: menu.text.includes(' ') && menu.text.length > 30 ? 'sentence' : 'word',
         definition: definition.text || undefined,
         contextSource: menu.source
      });
      setDefinition(prev => ({ ...prev, visible: false }));
  };

  const formatDefinition = (text: string) => {
      if (!text) return null;
      return text.split('\n\n').map((section, idx) => {
          const parts = section.split(':');
          if (parts.length > 1 && parts[0].length < 25) {
             return (
                 <div key={idx} className="mb-3">
                     <span className="text-[#00f3ff] font-bold uppercase text-[10px] tracking-widest">{parts[0]}:</span>
                     <p className="mt-1 text-zinc-300">{parts.slice(1).join(':').trim()}</p>
                 </div>
             );
          }
          return <p key={idx} className="mb-3 text-zinc-300">{section}</p>;
      });
  };

  return (
    <div className="fixed inset-0 z-[100] pointer-events-none font-sans text-left">
        {menu.visible && (
            <div 
                ref={menuRef}
                className="absolute bg-[#0a0a0c] border border-cyan-900/50 shadow-[0_0_20px_rgba(0,0,0,0.8)] rounded-sm overflow-hidden min-w-[180px] pointer-events-auto animate-fade-in origin-top-left z-[101]"
                style={{ top: menu.y, left: menu.x }}
            >
                <div className="px-3 py-2 bg-zinc-900 border-b border-zinc-800 text-[10px] text-zinc-500 font-mono uppercase truncate max-w-[200px]">
                    {menu.text.length > 20 ? menu.text.substring(0, 20) + '...' : menu.text}
                </div>
                <div className="p-1">
                    <button onClick={handleDefine} className="w-full text-left px-3 py-2 text-zinc-300 hover:bg-[#00f3ff]/10 hover:text-[#00f3ff] text-xs font-mono uppercase flex items-center gap-2 transition-colors rounded-sm"><Search size={14} />Explain / Define</button>
                    <button onClick={handleAddToNotebook} className="w-full text-left px-3 py-2 text-zinc-300 hover:bg-[#00f3ff]/10 hover:text-[#00f3ff] text-xs font-mono uppercase flex items-center gap-2 transition-colors rounded-sm"><FilePlus size={14} />Add to Notebook</button>
                    <button onClick={() => { navigator.clipboard.writeText(menu.text); setMenu(prev => ({ ...prev, visible: false })); }} className="w-full text-left px-3 py-2 text-zinc-500 hover:bg-zinc-800 hover:text-zinc-300 text-xs font-mono uppercase flex items-center gap-2 transition-colors rounded-sm"><Copy size={14} />Copy Text</button>
                </div>
            </div>
        )}

        {definition.visible && (
             <div 
                ref={defRef}
                className="absolute bg-[#050505]/95 backdrop-blur-md border border-[#00f3ff]/30 shadow-[0_0_30px_rgba(0,0,0,0.9)] rounded-lg p-5 w-80 pointer-events-auto animate-fade-in-up origin-top-left z-[102] max-h-[400px] flex flex-col"
                style={{ top: definition.position.y, left: definition.position.x }}
             >
                 <div className="flex items-start justify-between mb-3 shrink-0">
                     <h3 className="text-[#00f3ff] font-bold font-mono text-sm uppercase tracking-wider flex items-center gap-2">
                         <BookOpen size={16} />
                         {definition.isTranslated ? 'Translation' : 'Analysis'}
                     </h3>
                     <div className="flex items-center gap-2">
                         <button
                           onClick={handleTranslateToggle}
                           disabled={isTranslating || definition.loading || !definition.text}
                           className={`transition-colors p-1.5 rounded-sm hover:bg-zinc-900 ${definition.isTranslated || isTranslating ? 'text-[#00f3ff] bg-[#00f3ff]/10' : 'text-zinc-400 hover:text-[#00f3ff]'}`}
                           title={definition.isTranslated ? "Show Source Explanation" : `Translate Explanation to ${activeLanguage}`}
                         >
                            <Languages size={16} />
                         </button>
                         <button
                           onClick={handlePronounce}
                           disabled={isPlaying || definition.loading}
                           className={`text-zinc-400 hover:text-[#00f3ff] transition-colors p-1.5 rounded-sm hover:bg-zinc-900 ${isPlaying ? 'animate-pulse text-[#00f3ff] bg-[#00f3ff]/10' : ''}`}
                           title="Pronounce Selection"
                         >
                            <Volume2 size={16} />
                         </button>
                         <button onClick={() => setDefinition(prev => ({ ...prev, visible: false }))} className="text-zinc-600 hover:text-white transition-colors text-xl p-1">×</button>
                     </div>
                 </div>

                 <div className="mb-4 overflow-y-auto custom-scrollbar flex-1 text-sm">
                     {definition.loading ? (
                         <div className="flex items-center gap-2 text-zinc-500 text-xs font-mono py-2">
                             <Loader2 size={14} className="animate-spin" />
                             Decrypting Neural Data...
                         </div>
                     ) : (
                         <div className="leading-relaxed font-serif border-l-2 border-zinc-800 pl-3 animate-fade-in">
                             {formatDefinition(definition.text || "")}
                         </div>
                     )}
                 </div>

                 <button
                    onClick={handleSaveWithDefinition}
                    className="w-full py-2 bg-zinc-900 hover:bg-[#00f3ff]/20 text-zinc-400 hover:text-[#00f3ff] border border-zinc-800 hover:border-[#00f3ff]/50 rounded-sm text-xs font-mono uppercase transition-all flex items-center justify-center gap-2 shrink-0"
                 >
                     <FilePlus size={14} />
                     Save Analysis to Log
                 </button>
             </div>
        )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Film, Download, RotateCcw, Settings2, MonitorPlay, Globe, Square, RefreshCw, Play, Pause, RotateCw, Volume2, VolumeX, Maximize2, Minimize2, Gauge } from 'lucide-react';
import { Chapter, FileContext } from '../types';
import { generateSummaryVideo, hasValidKeyForVeo, requestVeoKey } from '../services/gemini';
import { Loader } from './ui/Loader';

interface Props {
  chapter: Chapter;
  fileContext: FileContext;
}

const STYLES = [
  'Cinematic', 'Anime', 'Photorealistic', 'Cartoon', 'Cyberpunk', 
  'Vaporwave', 'Noir', 'Documentary', 'Surreal'
];

const LANGUAGES = [
  'Original', 'Arabic', 'Chinese (Simplified)', 'Chinese (Traditional)', 'Dutch', 'English', 'French', 'German', 'Hindi', 'Indonesian', 'Italian', 'Japanese', 'Korean', 'Polish', 'Portuguese', 'Russian', 'Spanish', 'Swedish', 'Thai', 'Turkish', 'Vietnamese'
];

const RESOLUTIONS: ('720p' | '1080p' | '4K')[] = ['720p', '1080p', '4K'];
const SPEEDS = [0.5, 0.75, 1.0, 1.25, 1.5, 2.0];

export const VideoSummary: React.FC<Props> = ({ chapter, fileContext }) => {
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [status, setStatus] = useState<string>("");
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedStyle, setSelectedStyle] = useState('Cinematic');
  const [selectedLanguage, setSelectedLanguage] = useState('Original');
  const [selectedResolution, setSelectedResolution] = useState<'720p' | '1080p' | '4K'>('720p');

  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [playbackRate, setPlaybackRate] = useState(1.0);
  const [isMuted, setIsMuted] = useState(false);
  const [isFullScreen, setIsFullScreen] = useState(false);
  const [playbackProgress, setPlaybackProgress] = useState(0);
  const [controlsVisible, setControlsVisible] = useState(true);

  const abortRef = useRef<boolean>(false);
  const videoRef = useRef<HTMLVideoElement | null>(null);
  const containerRef = useRef<HTMLDivElement | null>(null);
  const controlsTimeoutRef = useRef<number | null>(null);

  useEffect(() => {
    return () => {
      if (videoUrl) URL.revokeObjectURL(videoUrl);
    };
  }, [videoUrl]);

  const handleToggleGeneration = async () => {
    if (isGenerating) {
        abortRef.current = true;
        setIsGenerating(false);
        setStatus("");
        return;
    }
    setError(null);
    setIsGenerating(true);
    abortRef.current = false;
    setStatus("Authenticating & Generating...");
    try {
      const hasKey = await hasValidKeyForVeo();
      if (!hasKey) {
        setStatus("Waiting for Access Key...");
        await requestVeoKey();
      }
      if (abortRef.current) return;

      const targetLang = selectedLanguage === 'Original' ? 'the source language of the document' : selectedLanguage;
      const url = await generateSummaryVideo(
        fileContext, 
        chapter, 
        setStatus, 
        selectedStyle, 
        targetLang,
        selectedResolution === '4K' ? '1080p' : selectedResolution as any
      );

      if (!abortRef.current) {
        if (videoUrl) URL.revokeObjectURL(videoUrl);
        setVideoUrl(url);
        setIsPlaying(false);
      }
    } catch (e: any) {
      if (!abortRef.current) {
        console.error(e);
        let msg = "Generation failed.";
        if (e.message?.includes("Requested entity was not found")) {
            msg = "Key Invalid. Paid project key required.";
            await requestVeoKey();
        } else if (e.message) msg = e.message;
        setError(msg);
      }
    } finally {
      if (!abortRef.current) {
        setIsGenerating(false);
        setStatus("");
      }
    }
  };

  const togglePlay = async (e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (!videoRef.current || !videoUrl) return;

    try {
      if (isPlaying) {
        videoRef.current.pause();
        setIsPlaying(false);
      } else {
        const playPromise = videoRef.current.play();
        if (playPromise !== undefined) {
          await playPromise;
          setIsPlaying(true);
        }
      }
    } catch (err) {
      console.warn("Playback interrupted or failed:", err);
      setIsPlaying(false);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = parseFloat(e.target.value);
    if (videoRef.current && duration) {
       videoRef.current.currentTime = (val / 100) * duration;
    }
  };

  const toggleMute = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (videoRef.current) {
        videoRef.current.muted = !isMuted;
        setIsMuted(!isMuted);
    }
  };

  const toggleFullScreen = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!containerRef.current) return;
    if (!document.fullscreenElement) {
        containerRef.current.requestFullscreen().catch(err => {
            console.error(`Error attempting to enable full-screen mode: ${err.message}`);
        });
    } else {
        document.exitFullscreen();
    }
  };

  const resetControlsTimeout = () => {
    setControlsVisible(true);
    if (controlsTimeoutRef.current) {
      window.clearTimeout(controlsTimeoutRef.current);
    }
    if (isPlaying) {
      controlsTimeoutRef.current = window.setTimeout(() => {
        setControlsVisible(false);
      }, 3000);
    }
  };

  useEffect(() => {
    const handleFsChange = () => {
      const isFs = !!document.fullscreenElement;
      setIsFullScreen(isFs);
      if (!isFs) setControlsVisible(true);
    };
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const formatTime = (seconds: number): string => {
    if (!seconds || isNaN(seconds)) return "00:00";
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const updateProgress = () => {
    if (videoRef.current) {
        setCurrentTime(videoRef.current.currentTime);
        setDuration(videoRef.current.duration || 0);
        setPlaybackProgress((videoRef.current.currentTime / (videoRef.current.duration || 1)) * 100);
    }
  };

  useEffect(() => {
    if (videoRef.current) {
        videoRef.current.playbackRate = playbackRate;
    }
  }, [playbackRate, videoUrl]);

  const currentStatusLabel = isGenerating ? "STOP" : videoUrl ? "REGENERATE" : "INITIATE";
  const currentStatusIcon = isGenerating ? <Square size={14} fill="currentColor" /> : videoUrl ? <RefreshCw size={14} /> : <Play size={14} fill="currentColor" />;

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 text-left overflow-hidden">
      {/* Top Controls Bar */}
      <div className="bg-zinc-950/80 p-3 rounded-lg border border-cyan-900/40 mb-3 flex items-center justify-between shrink-0 shadow-[0_0_15px_rgba(0,243,255,0.05)] w-full flex-wrap gap-2 z-20">
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono text-xs">
                 <MonitorPlay size={18} className="text-[#00f3ff]" />
                 <span>Cine_Render</span>
              </div>
          </div>
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                 <div className="p-1.5 text-zinc-500"><Settings2 size={16} /></div>
                 <select value={selectedStyle} onChange={(e) => setSelectedStyle(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]">{STYLES.map(t => <option key={t} value={t}>{t}</option>)}</select>
                 <div className="w-[1px] h-4 bg-zinc-700"></div>
                 <div className="p-1.5 text-zinc-500"><Maximize2 size={16} /></div>
                 <select value={selectedResolution} onChange={(e) => setSelectedResolution(e.target.value as any)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]">{RESOLUTIONS.map(res => <option key={res} value={res}>{res}</option>)}</select>
              </div>
              <button onClick={handleToggleGeneration} className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-bold font-mono uppercase transition-all shadow-[0_0_10px_rgba(0,243,255,0.3)] min-w-[120px] justify-center ${isGenerating ? 'bg-[#ff003c] text-white hover:bg-rose-600' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc]'}`}>
                {currentStatusIcon}
                {currentStatusLabel}
              </button>
          </div>
      </div>

      {/* Main Content Area - Player height synced to auto-fix window */}
      <div className="flex-1 flex flex-col items-center justify-start relative min-h-0 bg-[#020202] rounded-lg border border-zinc-900 shadow-inner overflow-hidden p-3">
        <div className="absolute inset-0 bg-grid opacity-[0.05] pointer-events-none"></div>

        {/* The Player Container - Auto height */}
        <div 
          ref={containerRef} 
          onMouseMove={resetControlsTimeout}
          className="relative w-full h-full flex flex-col bg-black shadow-2xl transition-all duration-500 group overflow-hidden shrink-0"
        >
            {/* Visual Screen */}
            <div className="flex-1 relative flex items-center justify-center overflow-hidden border-b border-zinc-900" onClick={() => videoUrl && togglePlay()}>
                {!videoUrl && !isGenerating && (
                    <div className="z-10 text-center space-y-4 p-8">
                        <div className="w-16 h-16 bg-zinc-900/50 rounded-full flex items-center justify-center mx-auto border border-zinc-800">
                             <Film className="text-zinc-700 w-6 h-6" />
                        </div>
                        <p className="text-zinc-600 font-mono text-[10px] uppercase tracking-widest">Awaiting Render Signal</p>
                        {error && <p className="text-[#ff003c] text-[9px] font-mono mt-2 border border-[#ff003c]/20 p-2 bg-[#ff003c]/5">ERROR: {error}</p>}
                    </div>
                )}

                {isGenerating && (
                    <div className="z-20 scale-75">
                         <Loader text={status} />
                    </div>
                )}

                {videoUrl && !isGenerating && (
                    <>
                        <video 
                            key={videoUrl}
                            ref={videoRef}
                            src={videoUrl ? `${videoUrl}#t=0.001` : undefined}
                            onTimeUpdate={updateProgress}
                            onLoadedMetadata={updateProgress}
                            onPlay={() => { 
                                setIsPlaying(true);
                                if(videoRef.current) videoRef.current.playbackRate = playbackRate;
                            }}
                            onPause={() => setIsPlaying(false)}
                            className="w-full h-full object-contain pointer-events-none"
                            playsInline
                        />
                        <div className={`absolute top-3 left-3 z-30 flex gap-2 transition-opacity duration-500 ${controlsVisible ? 'opacity-100' : 'opacity-0'}`}>
                             <div className="bg-black/60 backdrop-blur-md px-2 py-0.5 border border-cyan-500/30 rounded-sm text-[8px] font-mono text-cyan-400 uppercase tracking-widest">Live_Playback</div>
                             <div className="bg-black/60 backdrop-blur-md px-2 py-0.5 border border-zinc-800 rounded-sm text-[8px] font-mono text-zinc-500 uppercase tracking-widest">{selectedResolution}</div>
                        </div>
                    </>
                )}
            </div>

            {/* Control Bar - Matched to Net_Cast Spec */}
            <div className={`w-full bg-[#020202] relative z-40 shrink-0 transition-all duration-500 ${videoUrl && controlsVisible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-full pointer-events-none'}`}>
                {/* Progress Bar (Absolute Top of Control Bar) */}
                <div className="absolute top-0 left-0 w-full h-1 bg-zinc-800 hover:h-2 transition-all cursor-pointer z-50 group/progress">
                    <input 
                        type="range" 
                        min="0" max="100" step="0.1" 
                        value={playbackProgress} 
                        onChange={handleSeek} 
                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                    />
                    <div className="h-full bg-cyan-500 relative pointer-events-none" style={{ width: `${playbackProgress}%` }}>
                        <div className="absolute right-0 top-1/2 -translate-y-1/2 w-3 h-3 bg-cyan-100 rounded-full shadow-[0_0_10px_#00f3ff] opacity-0 group-hover/progress:opacity-100 transition-opacity"></div>
                    </div>
                </div>

                <div className="flex items-center justify-between p-3">
                    {/* Speed Controls (flex-1) */}
                    <div className="flex-1 flex items-center gap-2">
                        {SPEEDS.map(s => (
                            <button 
                                key={s} 
                                onClick={(e) => { e.stopPropagation(); setPlaybackRate(s); }} 
                                className={`text-[10px] font-mono font-bold transition-all ${playbackRate === s ? 'text-cyan-400' : 'text-zinc-600 hover:text-zinc-400'}`}
                            >
                                {s}x
                            </button>
                        ))}
                    </div>

                    {/* Primary Transport (flex-2) */}
                    <div className="flex-2 flex items-center justify-center gap-6">
                        <button onClick={(e) => { e.stopPropagation(); if(videoRef.current) videoRef.current.currentTime -= 5; }} className="text-zinc-500 hover:text-cyan-400 transition-colors"><RotateCcw size={20} /></button>
                        <button onClick={togglePlay} className={`w-10 h-10 rounded-full flex items-center justify-center transition-all ${isPlaying ? 'bg-transparent border-2 border-[#00f3ff] text-[#00f3ff] shadow-[0_0_15px_rgba(0,243,255,0.3)]' : 'bg-[#00f3ff] border-[#00f3ff] text-black shadow-[0_0_20px_rgba(0,243,255,0.6)] hover:scale-105'}`}>
                            {isPlaying ? <Pause size={18} fill="currentColor" /> : <Play size={18} fill="currentColor" className="ml-1" />}
                        </button>
                        <button onClick={(e) => { e.stopPropagation(); if(videoRef.current) videoRef.current.currentTime += 5; }} className="text-zinc-500 hover:text-cyan-400 transition-colors"><RotateCw size={20} /></button>
                    </div>

                    {/* Secondary Controls (flex-1) */}
                    <div className="flex-1 flex items-center justify-end gap-3">
                        <span className="text-[10px] font-mono text-zinc-600 min-w-[70px] text-right">{formatTime(currentTime)} / {formatTime(duration)}</span>
                        <button onClick={toggleMute} className="text-zinc-600 hover:text-cyan-400 transition-colors">
                            {isMuted ? <VolumeX size={18} /> : <Volume2 size={18} />}
                        </button>
                        <a href={videoUrl || '#'} download={`cine-render-${chapter.id}.mp4`} onClick={(e) => e.stopPropagation()} className="text-zinc-600 hover:text-cyan-400 transition-colors">
                            <Download size={18} />
                        </a>
                        <button onClick={toggleFullScreen} className="text-zinc-600 hover:text-cyan-400 transition-colors">
                            {isFullScreen ? <Minimize2 size={18} /> : <Maximize2 size={18} />}
                        </button>
                    </div>
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
